import SwiftUI

/// SwiftUI view that renders one embedded Nostr event by dispatching through
/// `NostrKindRegistry`. The view itself is purely declarative — it owns the
/// claim/release lifecycle of the embed URI (via `task(id:)` / `onDisappear`),
/// reads the resolved `EmbeddedEventEnvelope` from the host bound by the
/// caller, and lets the registry pick the right renderer.
///
/// Mirrors the TUI's `EmbeddedEvent` widget (`crates/nmp-cli/registry/tui/
/// content-kind-registry/embedded_event.rs`).
///
/// Lifecycle (D8 — no polling; aligned with task instructions to never claim
/// inside `var body`):
///   • `.task(id: uri)` calls the sink's `claim` exactly once per URI.
///   • `.onDisappear` releases. SwiftUI's identity-stable `id:` parameter
///     guarantees one matched claim/release pair per embedded slot.
public struct EmbeddedEvent: View {
    public var uri: String
    /// Optional resolved envelope. `nil` while the kernel fetches; the view
    /// shows a loading placeholder until the snapshot arrives.
    public var envelope: EmbeddedEventEnvelope?
    public var registry: NostrKindRegistry
    public var claimSink: EventClaimSinkProtocol?
    public var consumerId: String

    public init(
        uri: String,
        envelope: EmbeddedEventEnvelope?,
        registry: NostrKindRegistry,
        claimSink: EventClaimSinkProtocol? = nil,
        consumerId: String = "nmp-gallery-ios.embed"
    ) {
        self.uri = uri
        self.envelope = envelope
        self.registry = registry
        self.claimSink = claimSink
        self.consumerId = consumerId
    }

    public var body: some View {
        EmbedChromeContainer(
            depth: envelope?.depth ?? 0,
            collapsed: envelope?.collapsed ?? false
        ) {
            content
        }
        .task(id: uri) {
            claimSink?.claim(uri: uri, consumerId: consumerId)
        }
        .onDisappear {
            claimSink?.release(uri: uri, consumerId: consumerId)
        }
    }

    @ViewBuilder
    private var content: some View {
        if let envelope {
            if envelope.collapsed {
                let reason = envelope.collapseReason ?? "collapsed"
                Text("embedded event \(reason)")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            } else {
                registry.resolve(envelope.projection)
                    .body(projection: envelope.projection, registry: registry)
            }
        } else {
            // Loading state — the kernel is fetching the event. No spinner
            // (D8); show a subdued placeholder identical in shape to the
            // resolved render.
            VStack(alignment: .leading, spacing: 4) {
                Text("loading embedded event…")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                Text(shortUri(uri))
                    .font(.caption.monospaced())
                    .foregroundStyle(.secondary)
                    .lineLimit(1)
            }
        }
    }

    private func shortUri(_ value: String) -> String {
        guard value.count > 24 else { return value }
        return "\(value.prefix(14))…\(value.suffix(8))"
    }
}

/// Protocol mirror of `nmp_content::EventClaimSink`. The renderer fires
/// `claim(uri:consumerId:)` when an embed enters the view tree and the
/// matching `release(...)` when it leaves. Implementations forward to the
/// kernel's `nmp_app_claim_event` / `nmp_app_release_event` FFI symbols.
///
/// `Sendable` because the gallery's concrete impl is the kernel actor's
/// command channel — every method is fire-and-forget across threads.
public protocol EventClaimSinkProtocol: Sendable {
    func claim(uri: String, consumerId: String)
    func release(uri: String, consumerId: String)
}

import SwiftUI

/// Richer renderer for kind:30023 long-form articles (NIP-23).
///
/// Replaces `DefaultArticleRenderer` via `registry.setArticle(...)`. Renders:
///   • optional hero image (full-width, 16:9 crop)
///   • article title (large, semibold)
///   • optional summary line
///   • author chip: avatar + display name, styled as a NIP-65 byline
///
/// Mirrors the TUI's article renderer in
/// `crates/nmp-cli/registry/tui/content-kind-30023/`.
public struct ArticleEmbed: KindRenderer {
    public init() {}

    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .article(let article) = projection else {
            return AnyView(EmptyView())
        }

        let title = article.title?.trimmingCharacters(in: .whitespacesAndNewlines)
        let summary = article.summary?.trimmingCharacters(in: .whitespacesAndNewlines)
        let heroUrl = article.heroImageUrl.flatMap { URL(string: $0) }

        return AnyView(
            VStack(alignment: .leading, spacing: 10) {
                if let heroUrl {
                    AsyncImage(url: heroUrl) { phase in
                        switch phase {
                        case .success(let image):
                            image.resizable().scaledToFill()
                        default:
                            Rectangle().fill(Color.secondary.opacity(0.15))
                        }
                    }
                    .frame(maxWidth: .infinity)
                    .aspectRatio(16.0 / 9.0, contentMode: .fill)
                    .clipShape(RoundedRectangle(cornerRadius: 8))
                    .accessibilityHidden(true)
                }

                if let title, !title.isEmpty {
                    Text(title)
                        .font(.title3.weight(.semibold))
                        .foregroundStyle(.primary)
                        .fixedSize(horizontal: false, vertical: true)
                }

                if let summary, !summary.isEmpty {
                    Text(summary)
                        .font(.callout)
                        .foregroundStyle(.secondary)
                        .fixedSize(horizontal: false, vertical: true)
                }

                // Author byline.
                HStack(spacing: 8) {
                    NostrAvatar(
                        pubkey: article.authorPubkey,
                        pictureUrl: article.authorPictureUrl.flatMap(URL.init(string:)),
                        size: 24
                    )
                    Text(article.authorDisplayName ?? shortHex(article.authorPubkey))
                        .font(.caption.weight(.medium))
                        .foregroundStyle(.secondary)
                        .lineLimit(1)
                    Spacer(minLength: 0)
                    Text("article · kind:30023")
                        .font(.caption2.monospaced())
                        .foregroundStyle(.tertiary)
                }
            }
        )
    }

    private func shortHex(_ value: String) -> String {
        guard value.count > 10 else { return value }
        return "\(value.prefix(8))…"
    }
}

import SwiftUI

/// Richer renderer for kind:9802 highlights (NIP-84).
///
/// Replaces `DefaultHighlightRenderer` via `registry.setHighlight(...)`.
/// Renders:
///   • highlighted text styled like a pull-quote (italic, left-accent stripe,
///     subtle background)
///   • optional `context` line beneath the highlight (de-emphasized)
///   • source footer: `r` URL link, `e` event id chip, or `a` address chip
///   • author byline (avatar + display name)
///
/// Mirrors the TUI's highlight renderer in
/// `crates/nmp-cli/registry/tui/content-kind-9802/`.
public struct HighlightEmbed: KindRenderer {
    public init() {}

    public func body(
        projection: EmbedKindProjection,
        registry: NostrKindRegistry
    ) -> AnyView {
        guard case .highlight(let highlight) = projection else {
            return AnyView(EmptyView())
        }

        let author = highlight.authorDisplayName ?? shortHex(highlight.authorPubkey)

        return AnyView(
            VStack(alignment: .leading, spacing: 10) {
                // Pull-quote: italic body with a thin yellow accent stripe.
                HStack(alignment: .top, spacing: 10) {
                    RoundedRectangle(cornerRadius: 1.5)
                        .fill(Color.yellow.opacity(0.7))
                        .frame(width: 3)
                    VStack(alignment: .leading, spacing: 6) {
                        Text("\u{201C}\(highlight.highlightedText)\u{201D}")
                            .font(.body.italic())
                            .foregroundStyle(.primary)
                            .fixedSize(horizontal: false, vertical: true)
                        if let context = highlight.context?.trimmingCharacters(in: .whitespacesAndNewlines),
                           !context.isEmpty
                        {
                            Text(context)
                                .font(.caption)
                                .foregroundStyle(.secondary)
                                .fixedSize(horizontal: false, vertical: true)
                        }
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
                .padding(8)
                .background(Color.yellow.opacity(0.06), in: RoundedRectangle(cornerRadius: 6))

                // Source footer.
                sourceFooter(highlight: highlight)

                // Author byline.
                HStack(spacing: 8) {
                    Image(systemName: "highlighter")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                    Text("highlighted by \(author)")
                        .font(.caption.weight(.medium))
                        .foregroundStyle(.secondary)
                        .lineLimit(1)
                    Spacer(minLength: 0)
                    Text("kind:9802")
                        .font(.caption2.monospaced())
                        .foregroundStyle(.tertiary)
                }
            }
        )
    }

    @ViewBuilder
    private func sourceFooter(highlight: HighlightProjection) -> some View {
        if let url = highlight.sourceUrl, !url.isEmpty {
            Label {
                Text(url)
                    .lineLimit(1)
                    .truncationMode(.middle)
            } icon: {
                Image(systemName: "link")
            }
            .font(.caption.monospaced())
            .foregroundStyle(.tint)
        } else if let eventId = highlight.sourceEventId, !eventId.isEmpty {
            Label("note · \(shortHex(eventId))", systemImage: "doc.text")
                .font(.caption.monospaced())
                .foregroundStyle(.secondary)
        } else if let addr = highlight.sourceEventAddr, !addr.isEmpty {
            Label(addr, systemImage: "doc.richtext")
                .font(.caption.monospaced())
                .foregroundStyle(.secondary)
                .lineLimit(1)
                .truncationMode(.middle)
        }
    }

    private func shortHex(_ value: String) -> String {
        guard value.count > 10 else { return value }
        return "\(value.prefix(8))…"
    }
}

import SwiftUI
import UIKit

// MARK: - Info.plist requirement
//
// `UIApplication.shared.canOpenURL` only returns `true` for URL schemes that
// are listed in the *calling* app's Info.plist under `LSApplicationQueriesSchemes`.
// Without that entry the OS returns `false` even when the target app is installed.
//
// Add the following to your app's Info.plist:
//
//   <key>LSApplicationQueriesSchemes</key>
//   <array>
//     <string>nostrsigner</string>   <!-- Amber -->
//     <string>primal</string>        <!-- Primal -->
//     <string>nostrconnect</string>  <!-- generic NIP-46 bridge -->
//   </array>
//
// Re-export the list in NostrSignerDetector.knownSigners if you extend it.

// MARK: - NostrSignerInfo

/// Identity record for one locally-installed Nostr signer app.
public struct NostrSignerInfo: Identifiable, Equatable {

    /// Discriminator for first-class signers. Use `.generic` for any future
    /// signer that does not yet have an explicit case here.
    public enum SignerKind: Equatable {
        /// Amber — the canonical Android NIP-55 signer; also available on iOS
        /// via the `nostrsigner://` URL scheme.
        case amber
        /// Primal — registers the `primal://` scheme and can act as a remote
        /// signer via NIP-46 Nostr Connect.
        case primal
        /// Any other signer reachable via a named scheme.
        case generic(name: String, scheme: String)

        // NOTE: Olas does not currently register a URL scheme that other apps
        // can probe with canOpenURL (as of 2026-05-25). If Olas adds one in
        // the future, add `case olas` here and a matching entry in
        // NostrSignerDetector.knownSigners.

        public var scheme: String {
            switch self {
            case .amber:                    return "nostrsigner"
            case .primal:                   return "primal"
            case .generic(_, let scheme):   return scheme
            }
        }
    }

    public var kind: SignerKind

    /// Human-readable label shown in the signer card (e.g. "Amber").
    public var displayName: String

    /// URL scheme used for detection and deep-linking (e.g. "nostrsigner").
    public var urlScheme: String { kind.scheme }

    /// Stable identifier — uses the URL scheme so it survives reordering.
    public var id: String { urlScheme }

    public init(kind: SignerKind, displayName: String) {
        self.kind = kind
        self.displayName = displayName
    }
}

// MARK: - NostrSignerDetector

/// Probes the device for installed Nostr signer apps by testing URL scheme
/// reachability. Must be called from the main thread (UIApplication requires it).
///
/// Detection precedence matches the order of `knownSigners`: Amber → Primal →
/// nostrconnect-generic. Extend `knownSigners` as new iOS signer apps emerge.
public enum NostrSignerDetector {

    /// Ordered list of signers this detector knows about.
    /// All URL schemes here MUST also appear in Info.plist's
    /// `LSApplicationQueriesSchemes` — see the comment at the top of this file.
    public static let knownSigners: [NostrSignerInfo] = [
        NostrSignerInfo(kind: .amber, displayName: "Amber"),
        NostrSignerInfo(kind: .primal, displayName: "Primal"),
        NostrSignerInfo(
            kind: .generic(name: "Nostr Signer", scheme: "nostrconnect"),
            displayName: "Nostr Signer"
        ),
    ]

    /// Returns every known signer whose URL scheme the OS can open.
    /// Safe to call from a `.task { }` modifier — the Task runs on the actor
    /// that owns the view, which is `@MainActor`.
    @MainActor
    public static func detect() -> [NostrSignerInfo] {
        knownSigners.filter { canOpen($0.urlScheme) }
    }

    @MainActor
    private static func canOpen(_ scheme: String) -> Bool {
        guard let url = URL(string: "\(scheme)://") else { return false }
        return UIApplication.shared.canOpenURL(url)
    }
}

// MARK: - NostrLoginBlock

/// Login UI for Nostr apps using NMP.
///
/// Detects installed local signer apps (Amber, Primal, and other NIP-46/NIP-55
/// compatible signers) and surfaces them as one-tap sign-in options. Falls back
/// to a manual key-entry path when no external signers are found.
///
/// ## Usage
/// ```swift
/// NostrLoginBlock(
///     onSignerSelected: { signer in
///         // hand `signer.urlScheme` to your NIP-46 / NIP-55 bridge
///     },
///     onManualKey: {
///         // push your nsec / hex key entry view
///     }
/// )
/// ```
///
/// ## Theming
/// Inject a `NostrContentRenderer` into the environment to override text and
/// accent colors across the whole block:
/// ```swift
/// NostrLoginBlock(...)
///     .nostrContentRenderer(NostrContentRenderer(linkColor: .purple))
/// ```
public struct NostrLoginBlock: View {

    /// Called when the user taps a signer card. The app is responsible for
    /// initiating the NIP-46 / NIP-55 handshake with the chosen signer.
    public var onSignerSelected: (NostrSignerInfo) -> Void

    /// Called when the user taps "Enter your key" (manual nsec / hex path).
    public var onManualKey: () -> Void

    @State private var availableSigners: [NostrSignerInfo] = []

    @Environment(\.nostrContentRenderer) private var renderer

    public init(
        onSignerSelected: @escaping (NostrSignerInfo) -> Void,
        onManualKey: @escaping () -> Void
    ) {
        self.onSignerSelected = onSignerSelected
        self.onManualKey = onManualKey
    }

    public var body: some View {
        VStack(spacing: 16) {
            // Signer cards — one per detected app.
            ForEach(availableSigners) { signer in
                signerCard(for: signer)
            }

            // Manual key entry — always present.
            manualKeyButton

            // Install hint — only shown when no signers are installed.
            if availableSigners.isEmpty {
                installHint
            }
        }
        .task {
            availableSigners = NostrSignerDetector.detect()
        }
    }

    // MARK: - Sub-views

    private func signerCard(for signer: NostrSignerInfo) -> some View {
        Button {
            onSignerSelected(signer)
        } label: {
            HStack(spacing: 14) {
                signerIcon(for: signer)
                    .font(.title2)
                    .foregroundStyle(renderer.linkColor)
                    .frame(width: 32, alignment: .center)

                VStack(alignment: .leading, spacing: 2) {
                    Text(signer.displayName)
                        .font(.body.weight(.semibold))
                        .foregroundStyle(renderer.textColor)
                    Text("Sign in with \(signer.displayName)")
                        .font(.caption)
                        .foregroundStyle(renderer.secondaryTextColor)
                }

                Spacer(minLength: 0)

                Image(systemName: "chevron.right")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(renderer.secondaryTextColor)
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(renderer.quoteBackgroundColor, in: RoundedRectangle(cornerRadius: 12))
            .overlay(
                RoundedRectangle(cornerRadius: 12)
                    .stroke(renderer.quoteBorderColor, lineWidth: 0.5)
            )
        }
        .buttonStyle(.plain)
        .accessibilityLabel("Sign in with \(signer.displayName)")
    }

    private var manualKeyButton: some View {
        Button {
            onManualKey()
        } label: {
            HStack(spacing: 14) {
                Image(systemName: "key.fill")
                    .font(.title2)
                    .foregroundStyle(renderer.secondaryTextColor)
                    .frame(width: 32, alignment: .center)

                VStack(alignment: .leading, spacing: 2) {
                    Text("Enter your key")
                        .font(.body.weight(.semibold))
                        .foregroundStyle(renderer.textColor)
                    Text("Paste your nsec or hex private key")
                        .font(.caption)
                        .foregroundStyle(renderer.secondaryTextColor)
                }

                Spacer(minLength: 0)

                Image(systemName: "chevron.right")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(renderer.secondaryTextColor)
            }
            .padding(.horizontal, 16)
            .padding(.vertical, 14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(renderer.quoteBackgroundColor, in: RoundedRectangle(cornerRadius: 12))
            .overlay(
                RoundedRectangle(cornerRadius: 12)
                    .stroke(renderer.quoteBorderColor, lineWidth: 0.5)
            )
        }
        .buttonStyle(.plain)
        .accessibilityLabel("Enter your private key manually")
    }

    private var installHint: some View {
        HStack(spacing: 6) {
            Image(systemName: "info.circle")
                .font(.caption)
                .foregroundStyle(renderer.secondaryTextColor)
            Text("Install Amber or Primal for one-tap sign-in")
                .font(.caption)
                .foregroundStyle(renderer.secondaryTextColor)
                .multilineTextAlignment(.leading)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.horizontal, 4)
    }

    // MARK: - Helpers

    @ViewBuilder
    private func signerIcon(for signer: NostrSignerInfo) -> some View {
        switch signer.kind {
        case .amber:
            Image(systemName: "person.badge.key.fill")
        case .primal:
            Image(systemName: "bolt.fill")
        case .generic:
            Image(systemName: "arrow.up.forward.app.fill")
        }
    }
}

import SwiftUI

// MARK: - Wire types

/// One row of the kernel's `projections.relay_edit_rows` array.
///
/// `roleLabel` and `roleTint` are pre-formatted by the kernel
/// (`crates/nmp-core/src/actor/relay_roles.rs`) — do not reformat them
/// in Swift (aim.md §6.9 / display separation rule).
///
/// `roleTint` is a semantic token (`accent` | `info` | `success` |
/// `neutral`) emitted by `RELAY_ROLE_METADATA`. A 6-char hex string is
/// also accepted to stay forward-compatible if the kernel ever emits
/// custom palette colours; see `NostrRelayList.tintColor(for:)`.
public struct NostrRelayEditRow: Codable, Identifiable, Equatable {
    public var id: String { url }
    public let url: String
    public let role: String
    public let roleLabel: String
    public let roleTint: String

    public init(url: String, role: String, roleLabel: String, roleTint: String) {
        self.url = url
        self.role = role
        self.roleLabel = roleLabel
        self.roleTint = roleTint
    }

    private enum CodingKeys: String, CodingKey {
        case url
        case role
        case roleLabel = "role_label"
        case roleTint = "role_tint"
    }
}

/// One entry of the kernel's top-level `relay_statuses` snapshot field
/// (i.e. `snapshot.relay_statuses[]`, not nested inside `projections`).
///
/// `connection` is one of `connected | connecting | disconnected |
/// error` (closed token set). Callers typically fold the array into a
/// `[relay_url: connection]` dictionary before handing it to
/// `NostrRelayList`.
public struct NostrRelayConnectionStatus: Codable, Equatable {
    public let relayUrl: String
    public let connection: String
    public let reconnectCount: UInt32

    public init(relayUrl: String, connection: String, reconnectCount: UInt32) {
        self.relayUrl = relayUrl
        self.connection = connection
        self.reconnectCount = reconnectCount
    }

    private enum CodingKeys: String, CodingKey {
        case relayUrl = "relay_url"
        case connection
        case reconnectCount = "reconnect_count"
    }
}

// MARK: - Component

/// Relay list component — shows a user's configured relays with
/// connection-status dots and role badges.
///
/// Mirrors NDK's svelte `RelayList`. Data comes straight from the NMP
/// snapshot: rows from `projections.relay_edit_rows`, connection
/// statuses folded from the top-level `relay_statuses` field keyed by
/// relay URL.
public struct NostrRelayList: View {
    public let relays: [NostrRelayEditRow]
    /// Keyed by relay URL — caller merges from `relay_statuses` (typically
    /// `Dictionary(uniqueKeysWithValues: snapshot.relayStatuses.map { ($0.relayUrl, $0.connection) })`).
    public var connectionStatus: [String: String]
    public var onRelayTap: ((NostrRelayEditRow) -> Void)?

    public init(
        relays: [NostrRelayEditRow],
        connectionStatus: [String: String] = [:],
        onRelayTap: ((NostrRelayEditRow) -> Void)? = nil
    ) {
        self.relays = relays
        self.connectionStatus = connectionStatus
        self.onRelayTap = onRelayTap
    }

    public var body: some View {
        if relays.isEmpty {
            VStack {
                Text("No relays configured")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 24)
        } else {
            VStack(spacing: 0) {
                ForEach(relays) { relay in
                    RelayRow(
                        relay: relay,
                        connection: connectionStatus[relay.url],
                        onTap: onRelayTap.map { handler in { handler(relay) } }
                    )
                }
            }
        }
    }

    // MARK: Internals

    /// Resolve a relay-role tint token (or fallback hex) into a `Color`.
    ///
    /// The kernel currently emits semantic tokens (`accent`, `info`,
    /// `success`, `neutral`) — those are checked first. A 6-char hex
    /// string is also accepted via `Color(hex:)` to stay
    /// forward-compatible. Anything unrecognised falls back to
    /// `.secondary`.
    static func tintColor(for token: String) -> Color {
        switch token.lowercased() {
        case "accent": return .accentColor
        case "info": return .blue
        case "success": return .green
        case "warning": return .orange
        case "danger", "error": return .red
        case "neutral": return .secondary
        default:
            return Color(hex: token) ?? .secondary
        }
    }
}

// MARK: - Row

private struct RelayRow: View {
    let relay: NostrRelayEditRow
    let connection: String?
    let onTap: (() -> Void)?

    var body: some View {
        HStack(spacing: 10) {
            ConnectionDot(status: connection)

            Text(displayUrl)
                .font(.body.monospaced())
                .lineLimit(1)
                .truncationMode(.middle)
                .frame(maxWidth: .infinity, alignment: .leading)

            RoleBadge(
                label: relay.roleLabel,
                tint: NostrRelayList.tintColor(for: relay.roleTint)
            )
        }
        .padding(.vertical, 8)
        .padding(.horizontal, 12)
        .contentShape(Rectangle())
        .onTapGesture { onTap?() }
        .accessibilityElement(children: .combine)
        .accessibilityLabel("\(displayUrl), \(relay.roleLabel), \(accessibilityStatus)")
        .accessibilityAddTraits(onTap != nil ? .isButton : [])
    }

    private var displayUrl: String {
        if relay.url.hasPrefix("wss://") {
            return String(relay.url.dropFirst("wss://".count))
        }
        if relay.url.hasPrefix("ws://") {
            return String(relay.url.dropFirst("ws://".count))
        }
        return relay.url
    }

    private var accessibilityStatus: String {
        switch connection {
        case "connected": return "connected"
        case "connecting": return "connecting"
        case "error": return "error"
        case "disconnected": return "disconnected"
        default: return "status unknown"
        }
    }
}

// MARK: - Connection dot

private struct ConnectionDot: View {
    let status: String?

    @State private var pulse: Bool = false

    var body: some View {
        Circle()
            .fill(color)
            .frame(width: 8, height: 8)
            .opacity(isConnecting ? (pulse ? 0.4 : 1.0) : 1.0)
            .onAppear {
                guard isConnecting else { return }
                withAnimation(.easeInOut(duration: 0.8).repeatForever(autoreverses: true)) {
                    pulse = true
                }
            }
            .accessibilityHidden(true)
    }

    private var isConnecting: Bool { status == "connecting" }

    private var color: Color {
        switch status {
        case "connected": return .green
        case "connecting": return .orange
        case "error": return .red
        default: return .secondary
        }
    }
}

// MARK: - Role badge

private struct RoleBadge: View {
    let label: String
    let tint: Color

    var body: some View {
        Text(label)
            .font(.caption.weight(.medium))
            .foregroundStyle(.white)
            .padding(.horizontal, 6)
            .padding(.vertical, 2)
            .background(tint, in: RoundedRectangle(cornerRadius: 4, style: .continuous))
    }
}

// MARK: - Color(hex:)

private extension Color {
    /// Parse a 6-character RGB hex string (optionally prefixed with `#`).
    /// Returns `nil` if the input is not a valid 6-char hex.
    init?(hex: String) {
        let cleaned = hex.hasPrefix("#") ? String(hex.dropFirst()) : hex
        guard cleaned.count == 6,
              let rgb = UInt64(cleaned, radix: 16) else { return nil }
        self.init(
            red:   Double((rgb >> 16) & 0xFF) / 255,
            green: Double((rgb >>  8) & 0xFF) / 255,
            blue:  Double( rgb        & 0xFF) / 255
        )
    }
}

