@Composable
private fun MediaGroupBlock(urls: List<String>, kind: MediaKind) {
    when (kind) {
        MediaKind.Image -> {
            val nonEmpty = urls.filter { it.isNotEmpty() }
            if (nonEmpty.isNotEmpty()) {
                NostrMediaGrid(imageUrls = nonEmpty)
            }
        }
        MediaKind.Video, MediaKind.Audio -> {
            val first = urls.firstOrNull()
            if (first != null) {
                MediaRow(url = first, isAudio = kind == MediaKind.Audio)
            }
        }
    }
}

@Composable
private fun MediaRow(url: String, isAudio: Boolean) {
    val renderer = LocalNostrContentRenderer.current
    Row(
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(10.dp),
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(8.dp))
            .background(renderer.codeBackgroundColor)
            .clickable { renderer.callbacks.onLinkTap(url) }
            .padding(12.dp),
    ) {
        Icon(
            imageVector = if (isAudio) Icons.Filled.VolumeUp else Icons.Filled.PlayArrow,
            contentDescription = null,
            tint = renderer.linkColor,
        )
        Text(
            text = url.substringAfterLast('/').ifEmpty { url },
            color = renderer.secondaryTextColor,
            fontFamily = FontFamily.Monospace,
            maxLines = 1,
            style = MaterialTheme.typography.bodySmall,
        )
    }
}

@Composable
private fun EventRefBlock(
    uri: WireNostrUri,
    quoteCardProvider: ((WireNostrUri) -> NostrQuoteCardModel?)?,
) {
    // Variant selection mirrors SwiftUI: provider missing → .Collapsed,
    // provider hit → .Rich, provider miss → .Missing.
    val providedModel = quoteCardProvider?.invoke(uri)
    val variant: NostrQuoteCardVariant
    val model: NostrQuoteCardModel
    when {
        quoteCardProvider == null -> {
            variant = NostrQuoteCardVariant.Collapsed
            model = NostrQuoteCardModel(id = uri.primaryId, unresolvedUri = uri.uri)
        }
        providedModel != null -> {
            variant = NostrQuoteCardVariant.Rich
            model = providedModel
        }
        else -> {
            variant = NostrQuoteCardVariant.Missing
            model = NostrQuoteCardModel(id = uri.primaryId, unresolvedUri = uri.uri)
        }
    }
    val renderer = LocalNostrContentRenderer.current
    NostrQuoteCard(
        model = model,
        variant = variant,
        onTap = { renderer.callbacks.onEventRefTap(uri.primaryId) },
    )
}

@Composable
private fun CodeBlockBlock(info: String?, body: String) {
    val renderer = LocalNostrContentRenderer.current
    Column(
        verticalArrangement = Arrangement.spacedBy(4.dp),
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(6.dp))
            .background(renderer.codeBackgroundColor)
            .padding(10.dp),
    ) {
        if (!info.isNullOrEmpty()) {
            Text(
                text = info,
                color = renderer.secondaryTextColor,
                fontFamily = FontFamily.Monospace,
                style = MaterialTheme.typography.labelSmall,
            )
        }
        Text(
            text = body,
            color = renderer.textColor,
            fontFamily = FontFamily.Monospace,
            modifier = Modifier.fillMaxWidth(),
        )
    }
}

@Composable
private fun BlockQuoteBlock(
    children: List<UInt>,
    tree: ContentTreeWire,
    textStyle: TextStyle,
    mentionLabel: (WireNostrUri) -> String,
) {
    val renderer = LocalNostrContentRenderer.current
    val annotated = buildAnnotatedString {
        for (child in children) {
            appendInline(child, tree, renderer, mentionLabel)
        }
    }
    Row(
        horizontalArrangement = Arrangement.spacedBy(10.dp),
        modifier = Modifier
            .fillMaxWidth()
            .height(IntrinsicSize.Min)
            .padding(vertical = 4.dp),
    ) {
        Box(
            modifier = Modifier
                .width(3.dp)
                .fillMaxHeight()
                .background(renderer.quoteBorderColor),
        )
        Text(
            text = annotated,
            color = renderer.secondaryTextColor,
            style = textStyle.copy(fontStyle = FontStyle.Italic),
            modifier = Modifier.fillMaxWidth(),
        )
    }
}

@Composable
private fun ListBlock(
    orderedStart: ULong?,
    items: List<List<UInt>>,
    tree: ContentTreeWire,
    textStyle: TextStyle,
    mentionLabel: (WireNostrUri) -> String,
) {
    val renderer = LocalNostrContentRenderer.current
    Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
        items.forEachIndexed { offset, children ->
            val annotated = buildAnnotatedString {
                for (child in children) {
                    appendInline(child, tree, renderer, mentionLabel)
                }
            }
            Row(
                verticalAlignment = Alignment.Top,
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth(),
            ) {
                Text(
                    text = marker(orderedStart, offset),
                    color = renderer.secondaryTextColor,
                    style = textStyle,
                )
                Text(
                    text = annotated,
                    color = renderer.textColor,
                    style = textStyle,
                    modifier = Modifier.fillMaxWidth(),
                )
            }
        }
    }
}

private fun marker(orderedStart: ULong?, offset: Int): String {
    if (orderedStart != null) {
        return "${orderedStart + offset.toULong()}."
    }
    return "•"
}

@Composable
private fun RuleBlock() {
    val renderer = LocalNostrContentRenderer.current
    Spacer(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 4.dp)
            .height(1.dp)
            .background(renderer.quoteBorderColor),
    )
}

@Composable
private fun ImageBlock(alt: String, @Suppress("UNUSED_PARAMETER") title: String?, src: String?) {
    val renderer = LocalNostrContentRenderer.current
    if (!src.isNullOrEmpty()) {
        // `title` is reserved for a future accessibility label parity with the
        // SwiftUI implementation; the media grid currently only takes URLs.
        NostrMediaGrid(imageUrls = listOf(src))
        return
    }
    Text(
        text = if (alt.isEmpty()) "[image]" else "[$alt]",
        color = renderer.placeholderColor,
        style = MaterialTheme.typography.bodySmall,
    )
}

@Composable
private fun PlaceholderChip(reason: PlaceholderReason) {
    val renderer = LocalNostrContentRenderer.current
    val (label, icon) = when (reason) {
        PlaceholderReason.DepthLimit -> "Nested content collapsed" to Icons.Filled.ExpandMore
        PlaceholderReason.UnresolvedUri -> "Unresolved reference" to Icons.Filled.HelpOutline
    }
    Row(
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(6.dp),
        modifier = Modifier
            .clip(RoundedCornerShape(percent = 50))
            .background(renderer.codeBackgroundColor)
            .padding(horizontal = 8.dp, vertical = 4.dp),
    ) {
        Icon(imageVector = icon, contentDescription = null, tint = renderer.placeholderColor)
        Text(
            text = label,
            color = renderer.placeholderColor,
            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.SemiBold),
        )
    }
}

// Requires: nothing beyond the Kotlin stdlib. Kotlin 1.9+.
//
// Block-level grouping for a `ContentTreeWire`. `NostrContentView` consumes
// these in order; the grouping logic lives in its own file so the renderer
// composable stays focused on layout.

package nmp.content

/** Display level for inline-text groups; lets the renderer pick paragraph vs
 *  heading typography without re-walking the arena. */
public sealed class NostrContentInlineLevel {
    public object Paragraph : NostrContentInlineLevel()
    public data class Heading(val level: UByte) : NostrContentInlineLevel()
}

/** Block-level group produced by walking the roots of a [ContentTreeWire]. */
public sealed class NostrContentGroup {
    /** Inline runs that should be concatenated. The [children] are node
     *  indices; `UInt.MAX_VALUE` is a sentinel trailing newline used to
     *  separate adjacent paragraphs / headings. */
    public data class Inline(
        val level: NostrContentInlineLevel,
        val children: List<UInt>,
    ) : NostrContentGroup()

    public data class MediaGroup(val urls: List<String>, val kind: MediaKind) : NostrContentGroup()
    public data class EventRefGroup(val uri: WireNostrUri) : NostrContentGroup()
    public data class CodeBlockGroup(val info: String?, val body: String) : NostrContentGroup()
    public data class BlockQuoteGroup(val children: List<UInt>) : NostrContentGroup()
    public data class ListGroup(
        val orderedStart: ULong?,
        val items: List<List<UInt>>,
    ) : NostrContentGroup()
    public object RuleGroup : NostrContentGroup()
    public data class ImageGroup(
        val alt: String,
        val title: String?,
        val src: String?,
    ) : NostrContentGroup()
    public data class PlaceholderGroup(val reason: PlaceholderReason) : NostrContentGroup()
}

/** Sentinel index used to inject a trailing newline between contiguous inline
 *  groups (paragraph / heading). `UInt.MAX_VALUE` cannot reference a real
 *  arena slot — the bounds check in [ContentTreeWire.nodeAt] rejects it — so
 *  renderers can safely treat it as a newline marker. */
public val NOSTR_CONTENT_NEWLINE_SENTINEL: UInt = UInt.MAX_VALUE

/**
 * Flatten the document into a sequence of block-level groups. Mirrors the
 * `nostrContentGroups` function in the SwiftUI registry. Inline event refs
 * appearing inside paragraphs are pulled out into their own `EventRefGroup`
 * so the quote card renders block-level.
 */
public fun nostrContentGroups(tree: ContentTreeWire): List<NostrContentGroup> {
    val groups = mutableListOf<NostrContentGroup>()
    var pendingChildren = mutableListOf<UInt>()
    var pendingLevel: NostrContentInlineLevel = NostrContentInlineLevel.Paragraph

    fun flush() {
        if (pendingChildren.isNotEmpty()) {
            groups.add(NostrContentGroup.Inline(pendingLevel, pendingChildren.toList()))
            pendingChildren = mutableListOf()
            pendingLevel = NostrContentInlineLevel.Paragraph
        }
    }

    fun appendInline(level: NostrContentInlineLevel, children: List<UInt>) {
        if (pendingChildren.isNotEmpty() && pendingLevel != level) {
            flush()
        }
        pendingLevel = level

        val startCount = pendingChildren.size
        for (child in children) {
            val childNode = tree.nodeAt(child) ?: continue
            if (childNode is WireNode.EventRef) {
                flush()
                groups.add(NostrContentGroup.EventRefGroup(childNode.uri))
            } else {
                pendingChildren.add(child)
            }
        }
        if (pendingChildren.size > startCount) {
            pendingChildren.add(NOSTR_CONTENT_NEWLINE_SENTINEL)
        }
    }

    for (root in tree.roots) {
        val node = tree.nodeAt(root) ?: continue
        when (node) {
            is WireNode.Paragraph -> appendInline(NostrContentInlineLevel.Paragraph, node.children)
            is WireNode.Heading -> {
                flush()
                appendInline(NostrContentInlineLevel.Heading(node.level), node.children)
                flush()
            }
            is WireNode.Media -> {
                flush()
                groups.add(NostrContentGroup.MediaGroup(node.urls, node.mediaKind))
            }
            is WireNode.EventRef -> {
                flush()
                groups.add(NostrContentGroup.EventRefGroup(node.uri))
            }
            is WireNode.CodeBlock -> {
                flush()
                groups.add(NostrContentGroup.CodeBlockGroup(node.info, node.body))
            }
            is WireNode.BlockQuote -> {
                flush()
                groups.add(NostrContentGroup.BlockQuoteGroup(node.children))
            }
            is WireNode.ListNode -> {
                flush()
                groups.add(NostrContentGroup.ListGroup(node.orderedStart, node.items))
            }
            WireNode.Rule -> {
                flush()
                groups.add(NostrContentGroup.RuleGroup)
            }
            is WireNode.Image -> {
                flush()
                groups.add(NostrContentGroup.ImageGroup(node.alt, node.title, node.src))
            }
            is WireNode.Placeholder -> {
                flush()
                groups.add(NostrContentGroup.PlaceholderGroup(node.reason))
            }
            // Bare inline node at the root (plain text without paragraph wrap).
            // Treat it as a one-child paragraph.
            is WireNode.Text,
            is WireNode.Mention,
            is WireNode.Hashtag,
            is WireNode.Url,
            is WireNode.Emoji,
            is WireNode.Invoice,
            is WireNode.Emphasis,
            is WireNode.Strong,
            is WireNode.InlineCode,
            is WireNode.Link,
            WireNode.SoftBreak,
            WireNode.HardBreak -> appendInline(NostrContentInlineLevel.Paragraph, listOf(root))
        }
    }
    flush()
    return groups
}

use serde_json::Value;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContentTreeWire {
    pub nodes: Vec<WireNode>,
    pub roots: Vec<usize>,
    pub mode: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum WireNode {
    Text(String),
    Mention(WireUri),
    EventRef(WireUri),
    Hashtag(String),
    Url(String),
    Media {
        urls: Vec<String>,
        kind: String,
    },
    Emoji {
        shortcode: String,
        url: Option<String>,
    },
    Invoice {
        invoice: WireInvoice,
    },
    Paragraph {
        children: Vec<usize>,
    },
    Heading {
        level: u8,
        children: Vec<usize>,
    },
    BlockQuote {
        children: Vec<usize>,
    },
    CodeBlock {
        info: Option<String>,
        body: String,
    },
    List {
        ordered_start: Option<u64>,
        items: Vec<Vec<usize>>,
    },
    Rule,
    Emphasis {
        children: Vec<usize>,
    },
    Strong {
        children: Vec<usize>,
    },
    InlineCode(String),
    Link {
        children: Vec<usize>,
        href: Option<String>,
    },
    Image {
        alt: String,
        title: Option<String>,
        src: Option<String>,
    },
    SoftBreak,
    HardBreak,
    Placeholder {
        reason: String,
    },
    Unsupported,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WireUri {
    pub uri: String,
    pub kind: String,
    pub primary_id: String,
    pub relays: Vec<String>,
    pub author: Option<String>,
    pub event_kind: Option<u64>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WireInvoice {
    pub kind: String,
    pub value: String,
}

impl ContentTreeWire {
    pub fn from_value(value: &Value) -> Option<Self> {
        let nodes = value
            .get("nodes")?
            .as_array()?
            .iter()
            .map(WireNode::from_value)
            .collect::<Vec<_>>();
        let roots = value
            .get("roots")
            .and_then(Value::as_array)
            .into_iter()
            .flatten()
            .filter_map(|value| value.as_u64().and_then(|idx| usize::try_from(idx).ok()))
            .collect::<Vec<_>>();
        Some(Self {
            nodes,
            roots,
            mode: value
                .get("mode")
                .and_then(Value::as_str)
                .map(str::to_string),
        })
    }

    pub fn mentioned_pubkeys(&self) -> Vec<String> {
        let mut out = std::collections::BTreeSet::new();
        for node in &self.nodes {
            if let WireNode::Mention(uri) = node {
                if is_hex_id_64(&uri.primary_id) {
                    out.insert(uri.primary_id.clone());
                }
            }
        }
        out.into_iter().collect()
    }

    pub fn event_ref_ids(&self) -> Vec<String> {
        let mut out = std::collections::BTreeSet::new();
        for node in &self.nodes {
            if let WireNode::EventRef(uri) = node {
                if uri.kind == "event" && is_hex_id_64(&uri.primary_id) {
                    out.insert(uri.primary_id.clone());
                }
            }
        }
        out.into_iter().collect()
    }

    pub fn media_urls(&self) -> Vec<String> {
        let mut out = Vec::new();
        for node in &self.nodes {
            match node {
                WireNode::Media { urls, .. } => {
                    for url in urls {
                        push_unique(&mut out, url);
                    }
                }
                WireNode::Image { src: Some(src), .. } => push_unique(&mut out, src),
                _ => {}
            }
        }
        out
    }

    pub fn node(&self, index: usize) -> Option<&WireNode> {
        self.nodes.get(index)
    }

    pub fn inline_text(&self, children: &[usize]) -> String {
        children
            .iter()
            .filter_map(|idx| self.node(*idx))
            .map(|node| node.inline_label(self))
            .collect::<Vec<_>>()
            .join("")
    }
}

impl WireNode {
    fn from_value(value: &Value) -> Self {
        match value
            .get("kind")
            .and_then(Value::as_str)
            .unwrap_or_default()
        {
            "text" => Self::Text(string(value, "text")),
            "mention" => uri(value).map_or(Self::Unsupported, Self::Mention),
            "event_ref" => uri(value).map_or(Self::Unsupported, Self::EventRef),
            "hashtag" => Self::Hashtag(string(value, "tag")),
            "url" => Self::Url(string(value, "url")),
            "media" => Self::Media {
                urls: strings(value, "urls"),
                kind: string(value, "media_kind"),
            },
            "emoji" => Self::Emoji {
                shortcode: string(value, "shortcode"),
                url: value.get("url").and_then(Value::as_str).map(str::to_string),
            },
            "invoice" => {
                invoice(value).map_or(Self::Unsupported, |invoice| Self::Invoice { invoice })
            }
            "paragraph" => Self::Paragraph {
                children: indices(value, "children"),
            },
            "heading" => Self::Heading {
                level: value.get("level").and_then(Value::as_u64).unwrap_or(1) as u8,
                children: indices(value, "children"),
            },
            "block_quote" => Self::BlockQuote {
                children: indices(value, "children"),
            },
            "code_block" => Self::CodeBlock {
                info: value
                    .get("info")
                    .and_then(Value::as_str)
                    .map(str::to_string),
                body: string(value, "body"),
            },
            "list" => Self::List {
                ordered_start: value.get("ordered_start").and_then(Value::as_u64),
                items: value
                    .get("items")
                    .and_then(Value::as_array)
                    .into_iter()
                    .flatten()
                    .map(indices_array)
                    .collect(),
            },
            "rule" => Self::Rule,
            "emphasis" => Self::Emphasis {
                children: indices(value, "children"),
            },
            "strong" => Self::Strong {
                children: indices(value, "children"),
            },
            "inline_code" => Self::InlineCode(string(value, "code")),
            "link" => Self::Link {
                children: indices(value, "children"),
                href: value
                    .get("href")
                    .and_then(Value::as_str)
                    .map(str::to_string),
            },
            "image" => Self::Image {
                alt: string(value, "alt"),
                title: value
                    .get("title")
                    .and_then(Value::as_str)
                    .map(str::to_string),
                src: value.get("src").and_then(Value::as_str).map(str::to_string),
            },
            "soft_break" => Self::SoftBreak,
            "hard_break" => Self::HardBreak,
            "placeholder" => Self::Placeholder {
                reason: string(value, "reason"),
            },
            _ => Self::Unsupported,
        }
    }

    pub fn inline_label(&self, tree: &ContentTreeWire) -> String {
        match self {
            Self::Text(text) => text.clone(),
            Self::Mention(uri) => format!("@{}", short_id(&uri.primary_id)),
            Self::EventRef(uri) => format!("nostr:{}", short_id(&uri.primary_id)),
            Self::Hashtag(tag) => format!("#{tag}"),
            Self::Url(url) => url.clone(),
            Self::Emoji { shortcode, .. } => format!(":{shortcode}:"),
            Self::Invoice { invoice } => {
                format!("[{} invoice]", invoice.kind.to_ascii_lowercase())
            }
            Self::InlineCode(code) => format!("`{code}`"),
            Self::Paragraph { children }
            | Self::Heading { children, .. }
            | Self::BlockQuote { children } => tree.inline_text(children),
            Self::List {
                ordered_start,
                items,
            } => items
                .iter()
                .enumerate()
                .map(|(idx, item)| {
                    let marker = ordered_start
                        .map(|start| format!("{}.", start + idx as u64))
                        .unwrap_or_else(|| "-".to_string());
                    format!("{marker} {}", tree.inline_text(item))
                })
                .collect::<Vec<_>>()
                .join("\n"),
            Self::CodeBlock { body, .. } => body.clone(),
            Self::Media { urls, kind } => {
                format!("[{} media: {}]", kind.to_ascii_lowercase(), urls.len())
            }
            Self::Emphasis { children } | Self::Strong { children } => tree.inline_text(children),
            Self::Link { children, href } => {
                let label = tree.inline_text(children);
                if label.is_empty() {
                    href.clone().unwrap_or_default()
                } else {
                    label
                }
            }
            Self::SoftBreak => " ".to_string(),
            Self::HardBreak => "\n".to_string(),
            Self::Image { alt, title, .. } => title
                .as_ref()
                .map(|title| format!("[image: {alt} - {title}]"))
                .unwrap_or_else(|| format!("[image: {alt}]")),
            Self::Placeholder { reason } => format!("[{reason}]"),
            _ => String::new(),
        }
    }
}

fn uri(value: &Value) -> Option<WireUri> {
    let uri = value.get("uri")?;
    Some(WireUri {
        uri: string(uri, "uri"),
        kind: string(uri, "kind"),
        primary_id: string(uri, "primary_id"),
        relays: strings(uri, "relays"),
        author: uri
            .get("author")
            .and_then(Value::as_str)
            .map(str::to_string),
        event_kind: uri.get("event_kind").and_then(Value::as_u64),
    })
}

fn invoice(value: &Value) -> Option<WireInvoice> {
    let object = value.get("invoice")?.as_object()?;
    let (kind, payload) = object.iter().next()?;
    Some(WireInvoice {
        kind: kind.clone(),
        value: payload.as_str().unwrap_or_default().to_string(),
    })
}

fn string(value: &Value, key: &str) -> String {
    value
        .get(key)
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_string()
}

fn strings(value: &Value, key: &str) -> Vec<String> {
    value
        .get(key)
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_str)
        .map(str::to_string)
        .collect()
}

fn indices(value: &Value, key: &str) -> Vec<usize> {
    value.get(key).map(indices_array).unwrap_or_default()
}

fn indices_array(value: &Value) -> Vec<usize> {
    value
        .as_array()
        .into_iter()
        .flatten()
        .filter_map(|value| value.as_u64().and_then(|idx| usize::try_from(idx).ok()))
        .collect()
}

fn is_hex_id_64(value: &str) -> bool {
    value.len() == 64 && value.bytes().all(|b| b.is_ascii_hexdigit())
}

fn push_unique(out: &mut Vec<String>, value: &str) {
    if !value.is_empty() && !out.iter().any(|existing| existing == value) {
        out.push(value.to_string());
    }
}

fn short_id(id: &str) -> String {
    let count = id.chars().count();
    if count <= 12 {
        id.to_string()
    } else {
        let head = id.chars().take(6).collect::<String>();
        let tail = id
            .chars()
            .rev()
            .take(6)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<String>();
        format!("{head}…{tail}")
    }
}

use std::collections::BTreeMap;

use serde_json::Value;

use super::content_tree_wire::{ContentTreeWire, WireUri};

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct ContentRenderData {
    profiles: BTreeMap<String, ContentProfileRenderData>,
    events: BTreeMap<String, ContentEventRenderData>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContentProfileRenderData {
    pub pubkey: String,
    pub display_name: Option<String>,
    pub npub: Option<String>,
    pub picture_url: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ContentEventRenderData {
    pub id: String,
    pub author_pubkey: String,
    pub author_display_name: Option<String>,
    pub author_npub: Option<String>,
    pub kind: u64,
    pub created_at: u64,
    pub content_preview: String,
    pub content_tree: Option<ContentTreeWire>,
}

impl ContentRenderData {
    pub fn from_value(value: Option<&Value>) -> Self {
        let Some(value) = value else {
            return Self::default();
        };
        Self {
            profiles: map_values(value.get("profiles"), ContentProfileRenderData::from_value),
            events: map_values(value.get("events"), ContentEventRenderData::from_value),
        }
    }

    pub fn profile_for(&self, uri: &WireUri) -> Option<&ContentProfileRenderData> {
        self.profiles
            .get(&uri.primary_id)
            .or_else(|| self.profiles.get(&uri.uri))
    }

    pub fn event_for(&self, uri: &WireUri) -> Option<&ContentEventRenderData> {
        self.events
            .get(&uri.primary_id)
            .or_else(|| self.events.get(&uri.uri))
    }

    pub fn media_urls(&self) -> Vec<String> {
        let mut out = Vec::new();
        for event in self.events.values() {
            if let Some(tree) = event.content_tree.as_ref() {
                for url in tree.media_urls() {
                    if !out.iter().any(|existing| existing == &url) {
                        out.push(url);
                    }
                }
            }
        }
        out
    }
}

impl ContentProfileRenderData {
    fn from_value(key: &str, value: &Value) -> Option<Self> {
        let display = value.get("display").unwrap_or(value);
        Some(Self {
            pubkey: string(value, "pubkey")
                .or_else(|| string(display, "pubkey"))
                .unwrap_or_else(|| key.to_string()),
            display_name: string(display, "name")
                .or_else(|| string(value, "profile_name"))
                .or_else(|| string(value, "display_name")),
            npub: string(display, "npub").or_else(|| string(value, "npub")),
            picture_url: string(display, "picture_url")
                .or_else(|| string(value, "profile_picture"))
                .or_else(|| string(value, "picture_url")),
        })
    }

    pub fn label(&self) -> &str {
        self.display_name
            .as_deref()
            .or(self.npub.as_deref())
            .unwrap_or(&self.pubkey)
    }
}

impl ContentEventRenderData {
    fn from_value(key: &str, value: &Value) -> Option<Self> {
        let author_display = value.get("author_display").unwrap_or(value);
        Some(Self {
            id: string(value, "id").unwrap_or_else(|| key.to_string()),
            author_pubkey: string(value, "author_pubkey").unwrap_or_default(),
            author_display_name: string(author_display, "name")
                .or_else(|| string(value, "author_display_name")),
            author_npub: string(author_display, "npub").or_else(|| string(value, "author_npub")),
            kind: value.get("kind").and_then(Value::as_u64).unwrap_or(1),
            created_at: value.get("created_at").and_then(Value::as_u64).unwrap_or(0),
            content_preview: string(value, "content_preview").unwrap_or_default(),
            content_tree: value
                .get("content_tree")
                .and_then(ContentTreeWire::from_value),
        })
    }

    pub fn author_label(&self) -> &str {
        self.author_display_name
            .as_deref()
            .or(self.author_npub.as_deref())
            .unwrap_or(&self.author_pubkey)
    }
}

fn map_values<T>(
    value: Option<&Value>,
    parse: impl Fn(&str, &Value) -> Option<T>,
) -> BTreeMap<String, T> {
    let mut out = BTreeMap::new();
    let Some(value) = value else {
        return out;
    };
    if let Some(object) = value.as_object() {
        for (key, value) in object {
            if let Some(parsed) = parse(key, value) {
                out.insert(key.clone(), parsed);
            }
        }
    } else if let Some(array) = value.as_array() {
        for value in array {
            let key = string(value, "pubkey")
                .or_else(|| string(value, "id"))
                .or_else(|| string(value, "uri"))
                .unwrap_or_default();
            if !key.is_empty() {
                if let Some(parsed) = parse(&key, value) {
                    out.insert(key, parsed);
                }
            }
        }
    }
    out
}

fn string(value: &Value, key: &str) -> Option<String> {
    value
        .get(key)
        .and_then(Value::as_str)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

use ratatui::{
    style::Style,
    text::{Line, Span},
};

pub fn wrap_plain(value: &str, width: usize) -> Vec<Line<'static>> {
    wrap_words(value, width)
        .into_iter()
        .map(Line::from)
        .collect()
}

pub fn wrap_spans(spans: Vec<Span<'static>>, width: usize) -> Vec<Line<'static>> {
    if width == 0 {
        return vec![Line::from("")];
    }

    let mut lines = Vec::new();
    let mut current = Vec::new();
    let mut used = 0usize;

    for span in spans {
        let style = span.style;
        let text = span.content.to_string();
        let mut word = String::new();
        for ch in text.chars() {
            if ch == '\n' {
                push_piece(&mut lines, &mut current, &mut used, &word, style, width);
                word.clear();
                lines.push(line_from_spans(std::mem::take(&mut current)));
                used = 0;
            } else if ch.is_whitespace() {
                push_piece(&mut lines, &mut current, &mut used, &word, style, width);
                word.clear();
                if used > 0 && used < width {
                    current.push(Span::styled(" ".to_string(), style));
                    used += 1;
                }
            } else {
                word.push(ch);
            }
        }
        push_piece(&mut lines, &mut current, &mut used, &word, style, width);
    }

    if !current.is_empty() || lines.is_empty() {
        lines.push(line_from_spans(current));
    }
    lines
}

pub fn wrap_prefixed(
    value: &str,
    width: usize,
    prefix: &str,
    prefix_style: Style,
) -> Vec<Line<'static>> {
    let body_width = width.saturating_sub(prefix.chars().count()).max(1);
    wrap_words(value, body_width)
        .into_iter()
        .map(|line| {
            Line::from(vec![
                Span::styled(prefix.to_string(), prefix_style),
                Span::raw(line),
            ])
        })
        .collect()
}

fn push_piece(
    lines: &mut Vec<Line<'static>>,
    current: &mut Vec<Span<'static>>,
    used: &mut usize,
    piece: &str,
    style: Style,
    width: usize,
) {
    if piece.is_empty() {
        return;
    }
    for chunk in split_chars(piece, width) {
        let len = chunk.chars().count();
        if *used > 0 && *used + len > width {
            lines.push(line_from_spans(std::mem::take(current)));
            *used = 0;
        }
        current.push(Span::styled(chunk, style));
        *used += len;
    }
}

fn split_chars(value: &str, width: usize) -> Vec<String> {
    if value.chars().count() <= width {
        return vec![value.to_string()];
    }
    let mut out = Vec::new();
    let mut chunk = String::new();
    for ch in value.chars() {
        if chunk.chars().count() == width {
            out.push(std::mem::take(&mut chunk));
        }
        chunk.push(ch);
    }
    if !chunk.is_empty() {
        out.push(chunk);
    }
    out
}

fn line_from_spans(spans: Vec<Span<'static>>) -> Line<'static> {
    let out = spans
        .into_iter()
        .filter(|span| span.content != "\n")
        .collect::<Vec<_>>();
    Line::from(out)
}

fn wrap_words(value: &str, width: usize) -> Vec<String> {
    if width == 0 {
        return vec![String::new()];
    }
    let mut out = Vec::new();
    let mut line = String::new();
    for word in value.replace('\n', " ").split_whitespace() {
        let next = if line.is_empty() {
            word.to_string()
        } else {
            format!("{line} {word}")
        };
        if next.chars().count() > width && !line.is_empty() {
            out.push(std::mem::take(&mut line));
            line.push_str(word);
        } else {
            line = next;
        }
    }
    if !line.is_empty() || out.is_empty() {
        out.push(line);
    }
    out
}

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Paragraph, Widget, Wrap},
};

use super::{
    content_render_data::ContentRenderData,
    content_tree_wire::{ContentTreeWire, WireNode},
    nostr_mention_chip::NostrMentionChip,
    ratatui_text_wrap::wrap_spans,
};

/// Minimal inline renderer for text, mentions, hashtags, URLs, and breaks.
pub struct NostrMinimalContent<'a> {
    tree: &'a ContentTreeWire,
    render_data: Option<&'a ContentRenderData>,
}

impl<'a> NostrMinimalContent<'a> {
    pub fn new(tree: &'a ContentTreeWire) -> Self {
        Self {
            tree,
            render_data: None,
        }
    }

    pub fn render_data(mut self, render_data: Option<&'a ContentRenderData>) -> Self {
        self.render_data = render_data;
        self
    }

    pub fn lines(&self, width: usize) -> Vec<Line<'static>> {
        wrap_spans(self.spans(), width)
    }

    fn spans(&self) -> Vec<Span<'static>> {
        let mut spans = Vec::new();
        for root in &self.tree.roots {
            append_inline(self.tree, self.render_data, *root, &mut spans);
        }
        spans
    }
}

impl Widget for NostrMinimalContent<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        Paragraph::new(self.lines(area.width as usize))
            .wrap(Wrap { trim: false })
            .render(area, buf);
    }
}

fn append_inline(
    tree: &ContentTreeWire,
    render_data: Option<&ContentRenderData>,
    index: usize,
    spans: &mut Vec<Span<'static>>,
) {
    let Some(node) = tree.node(index) else {
        return;
    };
    match node {
        WireNode::Text(text) => spans.push(Span::raw(text.clone())),
        WireNode::Mention(uri) => spans.push(
            NostrMentionChip::new(uri)
                .profile(render_data.and_then(|data| data.profile_for(uri)))
                .span(),
        ),
        WireNode::Hashtag(tag) => spans.push(Span::styled(
            format!("#{tag}"),
            Style::default().fg(Color::Rgb(45, 212, 191)),
        )),
        WireNode::Url(url) => spans.push(Span::styled(
            url.clone(),
            Style::default().fg(Color::Rgb(96, 165, 250)),
        )),
        WireNode::InlineCode(code) => spans.push(Span::styled(
            format!("`{code}`"),
            Style::default().fg(Color::Rgb(253, 186, 116)),
        )),
        WireNode::EventRef(uri) => {
            let label = render_data
                .and_then(|data| data.event_for(uri))
                .map(|event| {
                    let body = if event.content_preview.is_empty() {
                        short_id(&event.id)
                    } else {
                        event.content_preview.clone()
                    };
                    format!("quote {}: {body}", event.author_label())
                })
                .unwrap_or_else(|| format!("quote {}", short_id(&uri.primary_id)));
            spans.push(Span::styled(
                label,
                Style::default().fg(Color::Rgb(196, 181, 253)),
            ));
        }
        WireNode::Emoji { shortcode, .. } => spans.push(Span::raw(format!(":{shortcode}:"))),
        WireNode::Invoice { invoice } => spans.push(Span::styled(
            format!("[{} invoice]", invoice.kind.to_ascii_lowercase()),
            Style::default().fg(Color::Rgb(250, 204, 21)),
        )),
        WireNode::SoftBreak => spans.push(Span::raw(" ")),
        WireNode::HardBreak => spans.push(Span::raw("\n")),
        WireNode::Paragraph { children }
        | WireNode::Emphasis { children }
        | WireNode::Strong { children }
        | WireNode::Link { children, .. } => {
            for child in children {
                append_inline(tree, render_data, *child, spans);
            }
        }
        WireNode::Image { alt, src, .. } => {
            let target = src.as_deref().unwrap_or("missing src");
            spans.push(Span::styled(
                format!("[image: {alt} {target}]"),
                Style::default().fg(Color::Rgb(186, 230, 253)),
            ));
        }
        WireNode::Media { urls, kind } => spans.push(Span::styled(
            format!("[{} media: {}]", kind.to_ascii_lowercase(), urls.len()),
            Style::default().fg(Color::Rgb(186, 230, 253)),
        )),
        _ => {
            let label = node.inline_label(tree);
            if !label.is_empty() {
                spans.push(Span::raw(label));
            }
        }
    }
}

fn short_id(id: &str) -> String {
    let count = id.chars().count();
    if count <= 12 {
        id.to_string()
    } else {
        let head = id.chars().take(6).collect::<String>();
        let tail = id
            .chars()
            .rev()
            .take(6)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<String>();
        format!("{head}…{tail}")
    }
}

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Paragraph, Widget},
};

use super::{content_render_data::ContentProfileRenderData, content_tree_wire::WireUri};

/// Inline terminal chip for a pre-resolved profile mention.
pub struct NostrMentionChip<'a> {
    uri: &'a WireUri,
    profile: Option<&'a ContentProfileRenderData>,
    style: Style,
}

impl<'a> NostrMentionChip<'a> {
    pub fn new(uri: &'a WireUri) -> Self {
        Self {
            uri,
            profile: None,
            style: Style::default()
                .fg(mention_color(&uri.primary_id))
                .add_modifier(Modifier::BOLD),
        }
    }

    pub fn profile(mut self, profile: Option<&'a ContentProfileRenderData>) -> Self {
        self.profile = profile;
        self
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }

    pub fn label(&self) -> String {
        let raw = self
            .profile
            .map(ContentProfileRenderData::label)
            .unwrap_or(&self.uri.primary_id);
        let label = self
            .profile
            .and_then(|profile| profile.display_name.as_deref())
            .map(str::to_string)
            .unwrap_or_else(|| short_id(raw));
        format!("@{label}")
    }

    pub fn span(&self) -> Span<'static> {
        Span::styled(self.label(), self.style)
    }
}

impl Widget for NostrMentionChip<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        Paragraph::new(Line::from(self.span())).render(area, buf);
    }
}

fn short_id(id: &str) -> String {
    let count = id.chars().count();
    if count <= 12 {
        id.to_string()
    } else {
        let head = id.chars().take(6).collect::<String>();
        let tail = id
            .chars()
            .rev()
            .take(6)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<String>();
        format!("{head}…{tail}")
    }
}

fn mention_color(id: &str) -> Color {
    let hue = stable_hash(id) % 360;
    let (r, g, b) = hsl_to_rgb(hue as f32, 0.72, 0.66);
    Color::Rgb(r, g, b)
}

fn stable_hash(value: &str) -> u32 {
    value.bytes().fold(5381u32, |hash, byte| {
        hash.wrapping_mul(33) ^ u32::from(byte)
    })
}

fn hsl_to_rgb(h: f32, s: f32, l: f32) -> (u8, u8, u8) {
    let c = (1.0 - (2.0 * l - 1.0).abs()) * s;
    let h_prime = h / 60.0;
    let x = c * (1.0 - (h_prime % 2.0 - 1.0).abs());
    let (r1, g1, b1) = match h_prime {
        h if (0.0..1.0).contains(&h) => (c, x, 0.0),
        h if (1.0..2.0).contains(&h) => (x, c, 0.0),
        h if (2.0..3.0).contains(&h) => (0.0, c, x),
        h if (3.0..4.0).contains(&h) => (0.0, x, c),
        h if (4.0..5.0).contains(&h) => (x, 0.0, c),
        _ => (c, 0.0, x),
    };
    let m = l - c / 2.0;
    (channel(r1 + m), channel(g1 + m), channel(b1 + m))
}

fn channel(value: f32) -> u8 {
    (value.clamp(0.0, 1.0) * 255.0).round() as u8
}

