        let first =
            mention_color("1111111111111111111111111111111111111111111111111111111111111111");
        let second =
            mention_color("1111111111111111111111111111111111111111111111111111111111111111");
        let other =
            mention_color("2222222222222222222222222222222222222222222222222222222222222222");
        assert_eq!(first, second);
        assert_ne!(first, other);
    }
}

