use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Widget},
};
use ratatui_image::protocol::Protocol;

use super::{
    content_render_data::{ContentEventRenderData, ContentRenderData},
    content_tree_wire::{ContentTreeWire, WireNode},
    nostr_media_grid::NostrMediaGrid,
    ratatui_text_wrap::wrap_prefixed,
};

/// Terminal quote/event reference card.
pub struct NostrQuoteCard<'a> {
    tree: &'a ContentTreeWire,
    node: &'a WireNode,
    render_data: Option<&'a ContentRenderData>,
    media_images: &'a [(&'a str, &'a Protocol)],
    style: Style,
}

impl<'a> NostrQuoteCard<'a> {
    pub fn new(tree: &'a ContentTreeWire, node: &'a WireNode) -> Self {
        Self {
            tree,
            node,
            render_data: None,
            media_images: &[],
            style: Style::default().fg(Color::Rgb(203, 213, 225)),
        }
    }

    pub fn render_data(mut self, render_data: Option<&'a ContentRenderData>) -> Self {
        self.render_data = render_data;
        self
    }

    pub fn media_images(mut self, images: &'a [(&'a str, &'a Protocol)]) -> Self {
        self.media_images = images;
        self
    }

    pub fn lines(&self, width: usize) -> Vec<Line<'static>> {
        match self.node {
            WireNode::EventRef(uri) => {
                if let Some(event) = self.render_data.and_then(|data| data.event_for(uri)) {
                    let header = format!("quote {} · kind:{}", event.author_label(), event.kind);
                    let mut lines = vec![Line::from(Span::styled(
                        header,
                        Style::default().fg(Color::Rgb(148, 163, 184)),
                    ))];
                    let body = if event.content_preview.is_empty() {
                        short_id(&event.id)
                    } else {
                        event.content_preview.clone()
                    };
                    lines.extend(wrap_prefixed(&body, width, "  ", muted_style()));
                    lines
                } else {
                    vec![Line::from(vec![
                        Span::styled("quote ", Style::default().fg(Color::Rgb(148, 163, 184))),
                        Span::styled(short_id(&uri.primary_id), self.style),
                    ])]
                }
            }
            WireNode::BlockQuote { children } => self
                .text_for_nodes(children)
                .split('\n')
                .flat_map(|line| wrap_prefixed(line, width, "> ", muted_style()))
                .collect(),
            _ => Vec::new(),
        }
    }

    pub fn preferred_height(&self, width: usize) -> u16 {
        let inner_width = width.saturating_sub(2);
        match self.node {
            WireNode::EventRef(uri) => self
                .render_data
                .and_then(|data| data.event_for(uri))
                .map(|event| 2 + 1 + self.event_body_height(event, inner_width.saturating_sub(2)))
                .unwrap_or_else(|| self.lines(inner_width).len() as u16 + 2),
            _ => self.lines(inner_width).len() as u16 + 2,
        }
        .max(3)
    }

    fn text_for_nodes(&self, children: &[usize]) -> String {
        children
            .iter()
            .filter_map(|idx| self.tree.node(*idx))
            .map(|node| node.inline_label(self.tree))
            .filter(|text| !text.is_empty())
            .collect::<Vec<_>>()
            .join("\n")
    }
}

impl Widget for NostrQuoteCard<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let block = Block::default()
            .borders(Borders::ALL)
            .border_style(Style::default().fg(Color::Rgb(71, 85, 105)));
        let inner = block.inner(area);
        block.render(area, buf);
        match self.node {
            WireNode::EventRef(uri) => {
                if let Some(event) = self.render_data.and_then(|data| data.event_for(uri)) {
                    self.render_event(event, inner, buf);
                } else {
                    Paragraph::new(self.lines(inner.width as usize)).render(inner, buf);
                }
            }
            _ => Paragraph::new(self.lines(inner.width as usize)).render(inner, buf),
        }
    }
}

impl NostrQuoteCard<'_> {
    fn render_event(&self, event: &ContentEventRenderData, area: Rect, buf: &mut Buffer) {
        if area.is_empty() {
            return;
        }
        let header = format!("quote {} · kind:{}", event.author_label(), event.kind);
        Paragraph::new(Line::from(Span::styled(header, muted_style())))
            .render(Rect { height: 1, ..area }, buf);

        let mut cursor = area.y.saturating_add(1);
        let body_area = Rect {
            x: area.x.saturating_add(2),
            y: cursor,
            width: area.width.saturating_sub(2),
            height: area.bottom().saturating_sub(cursor),
        };
        if let Some(tree) = event.content_tree.as_ref() {
            self.render_tree(tree, body_area, buf, &mut cursor);
        } else {
            let body = if event.content_preview.is_empty() {
                short_id(&event.id)
            } else {
                event.content_preview.clone()
            };
            render_lines(
                wrap_prefixed(&body, body_area.width as usize, "", muted_style()),
                body_area,
                buf,
                &mut cursor,
            );
        }
    }

    fn render_tree(&self, tree: &ContentTreeWire, area: Rect, buf: &mut Buffer, cursor: &mut u16) {
        for root in &tree.roots {
            self.render_tree_node(tree, *root, area, buf, cursor);
            if *cursor >= area.bottom() {
                break;
            }
        }
    }

    fn render_tree_node(
        &self,
        tree: &ContentTreeWire,
        index: usize,
        area: Rect,
        buf: &mut Buffer,
        cursor: &mut u16,
    ) {
        let Some(node) = tree.node(index) else {
            return;
        };
        match node {
            WireNode::Paragraph { children } => {
                let mut text = String::new();
                for child in children {
                    let Some(child_node) = tree.node(*child) else {
                        continue;
                    };
                    match child_node {
                        WireNode::Media { urls, kind } => {
                            render_plain(&mut text, area, buf, cursor);
                            self.render_media(urls, kind, area, buf, cursor);
                        }
                        WireNode::Image { src, .. } => {
                            render_plain(&mut text, area, buf, cursor);
                            if let Some(src) = src {
                                self.render_media(
                                    std::slice::from_ref(src),
                                    "image",
                                    area,
                                    buf,
                                    cursor,
                                );
                            }
                        }
                        _ => text.push_str(&child_node.inline_label(tree)),
                    }
                }
                render_plain(&mut text, area, buf, cursor);
            }
            WireNode::Media { urls, kind } => self.render_media(urls, kind, area, buf, cursor),
            WireNode::Image { src, .. } => {
                if let Some(src) = src {
                    self.render_media(std::slice::from_ref(src), "image", area, buf, cursor);
                }
            }
            _ => {
                let mut text = node.inline_label(tree);
                render_plain(&mut text, area, buf, cursor);
            }
        }
    }

    fn render_media(
        &self,
        urls: &[String],
        kind: &str,
        area: Rect,
        buf: &mut Buffer,
        cursor: &mut u16,
    ) {
        let grid = NostrMediaGrid::new(urls, kind).images(self.media_images);
        let rect = take_area(area, cursor, grid.preferred_height());
        if rect.is_empty() {
            return;
        }
        grid.render(rect, buf);
        *cursor = rect.bottom().saturating_add(1).min(area.bottom());
    }

    fn event_body_height(&self, event: &ContentEventRenderData, width: usize) -> u16 {
        if let Some(tree) = event.content_tree.as_ref() {
            tree.roots
                .iter()
                .filter_map(|root| tree.node(*root))
                .map(|node| self.node_height(tree, node, width))
                .sum::<u16>()
                .max(1)
        } else {
            wrap_prefixed(&event.content_preview, width, "", muted_style()).len() as u16
        }
    }

    fn node_height(&self, tree: &ContentTreeWire, node: &WireNode, width: usize) -> u16 {
        match node {
            WireNode::Media { urls, kind } => NostrMediaGrid::new(urls, kind)
                .images(self.media_images)
                .preferred_height()
                .saturating_add(1),
            WireNode::Image { src, .. } => src
                .as_ref()
                .map(|src| {
                    NostrMediaGrid::new(std::slice::from_ref(src), "image")
                        .images(self.media_images)
                        .preferred_height()
                        .saturating_add(1)
                })
                .unwrap_or(0),
            _ => wrap_prefixed(&node.inline_label(tree), width, "", muted_style()).len() as u16,
        }
    }
}

fn render_plain(text: &mut String, area: Rect, buf: &mut Buffer, cursor: &mut u16) {
    if text.trim().is_empty() {
        text.clear();
        return;
    }
    let lines = wrap_prefixed(text, area.width as usize, "", muted_style());
    render_lines(lines, area, buf, cursor);
    text.clear();
}

fn render_lines(lines: Vec<Line<'static>>, area: Rect, buf: &mut Buffer, cursor: &mut u16) {
    let rect = take_area(area, cursor, lines.len() as u16);
    if rect.is_empty() {
        return;
    }
    Paragraph::new(lines).render(rect, buf);
    *cursor = rect.bottom();
}

fn take_area(area: Rect, cursor: &mut u16, wanted_height: u16) -> Rect {
    if *cursor >= area.bottom() || wanted_height == 0 {
        return Rect::new(area.x, area.bottom(), area.width, 0);
    }
    let available = area.bottom().saturating_sub(*cursor);
    Rect {
        x: area.x,
        y: *cursor,
        width: area.width,
        height: wanted_height.min(available),
    }
}

fn muted_style() -> Style {
    Style::default().fg(Color::Rgb(148, 163, 184))
}

fn short_id(id: &str) -> String {
    let count = id.chars().count();
    if count <= 12 {
        id.to_string()
    } else {
        let head = id.chars().take(6).collect::<String>();
        let tail = id
            .chars()
            .rev()
            .take(6)
            .collect::<Vec<_>>()
            .into_iter()
            .rev()
            .collect::<String>();
        format!("{head}…{tail}")
    }
}

//! TUI content-kind-registry component (F-CR-06).

pub mod embed_chrome_container;
pub mod embedded_event;
pub mod kind_renderer;
pub mod nostr_kind_registry;

pub use embedded_event::EmbeddedEvent;
pub use kind_renderer::{KindRenderer, KindRendererRef};
pub use nostr_kind_registry::{
    DefaultArticleRenderer, DefaultHighlightRenderer, DefaultProfileRenderer,
    DefaultShortNoteRenderer, DefaultUnknownRenderer, NostrKindRegistry,
};

//! KindRenderer trait for TUI kind-dispatched content rendering (F-CR-06).
//!
//! See ADR-0034 for the cross-platform projection contract.

use ratatui::{buffer::Buffer, layout::Rect};
use std::sync::Arc;

use nmp_content::context::RenderContext;
use nmp_content::embed_projection::EmbedKindProjection;

use super::NostrKindRegistry;

/// Trait for a renderer of one specific `EmbedKindProjection` variant (or
/// a group of unknown kinds).
pub trait KindRenderer: Send + Sync {
    fn render(
        &self,
        projection: &EmbedKindProjection,
        ctx: &RenderContext,
        registry: &NostrKindRegistry,
        area: Rect,
        buf: &mut Buffer,
    );

    fn preferred_height(&self, projection: &EmbedKindProjection, width: u16) -> u16;
}

pub type KindRendererRef = Arc<dyn KindRenderer>;

//! NostrKindRegistry for the TUI (F-CR-06).
//!
//! Single source of truth for kind → renderer dispatch in the terminal.

use std::collections::HashMap;
use std::sync::Arc;

use nmp_content::embed_projection::EmbedKindProjection;
use nmp_content::wire::{ContentTreeWire, WireNode};

use ratatui::style::{Color, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Paragraph, Widget, Wrap};

use super::kind_renderer::{KindRenderer, KindRendererRef};

/// The registry consulted by `EmbeddedEvent` (and by `NostrContentView`).
pub struct NostrKindRegistry {
    short_note: Option<KindRendererRef>,
    article: Option<KindRendererRef>,
    highlight: Option<KindRendererRef>,
    profile: Option<KindRendererRef>,
    unknown_by_kind: HashMap<u32, KindRendererRef>,
    fallback: KindRendererRef,
}

impl NostrKindRegistry {
    pub fn new(fallback: KindRendererRef) -> Self {
        Self {
            short_note: None,
            article: None,
            highlight: None,
            profile: None,
            unknown_by_kind: HashMap::new(),
            fallback,
        }
    }

    /// Installs the built-in default renderer for each known projection variant,
    /// plus `DefaultUnknownRenderer` as the fallback for unregistered numeric kinds.
    /// Replace any slot with `set_*` to swap in a richer handler (e.g. F-CR-09).
    pub fn make_default() -> Self {
        let mut reg = Self::new(Arc::new(DefaultUnknownRenderer));
        reg.short_note = Some(Arc::new(DefaultShortNoteRenderer));
        reg.article = Some(Arc::new(DefaultArticleRenderer));
        reg.highlight = Some(Arc::new(DefaultHighlightRenderer));
        reg.profile = Some(Arc::new(DefaultProfileRenderer));
        reg
    }

    pub fn set_short_note(&mut self, r: KindRendererRef) {
        self.short_note = Some(r);
    }

    pub fn set_article(&mut self, r: KindRendererRef) {
        self.article = Some(r);
    }

    pub fn set_highlight(&mut self, r: KindRendererRef) {
        self.highlight = Some(r);
    }

    pub fn set_profile(&mut self, r: KindRendererRef) {
        self.profile = Some(r);
    }

    pub fn register_unknown(&mut self, kind: u32, r: KindRendererRef) {
        self.unknown_by_kind.insert(kind, r);
    }

    pub fn resolve(&self, projection: &EmbedKindProjection) -> &dyn KindRenderer {
        match projection {
            EmbedKindProjection::ShortNote(_) => {
                self.short_note.as_deref().unwrap_or(self.fallback.as_ref())
            }
            EmbedKindProjection::Article(_) => {
                self.article.as_deref().unwrap_or(self.fallback.as_ref())
            }
            EmbedKindProjection::Highlight(_) => {
                self.highlight.as_deref().unwrap_or(self.fallback.as_ref())
            }
            EmbedKindProjection::Profile(_) => {
                self.profile.as_deref().unwrap_or(self.fallback.as_ref())
            }
            EmbedKindProjection::Unknown(p) => self
                .unknown_by_kind
                .get(&p.kind)
                .map(|r| r.as_ref())
                .unwrap_or(self.fallback.as_ref()),
        }
    }
}

/// Default renderer for `ShortNoteProjection` (kind:1 quoted notes).
pub struct DefaultShortNoteRenderer;

impl KindRenderer for DefaultShortNoteRenderer {
    fn render(
        &self,
        projection: &EmbedKindProjection,
        _ctx: &nmp_content::context::RenderContext,
        _registry: &NostrKindRegistry,
        area: ratatui::layout::Rect,
        buf: &mut ratatui::buffer::Buffer,
    ) {
        let EmbedKindProjection::ShortNote(note) = projection else {
            return;
        };
        let author = note
            .author_display_name
            .clone()
            .unwrap_or_else(|| short_id(&note.author_pubkey));
        render_two_line(
            &format!("note · {author}"),
            &tree_text(&note.content_tree),
            area,
            buf,
        );
    }

    fn preferred_height(&self, projection: &EmbedKindProjection, width: u16) -> u16 {
        let EmbedKindProjection::ShortNote(note) = projection else {
            return 2;
        };
        text_height(&tree_text(&note.content_tree), width)
            .saturating_add(1)
            .max(2)
    }
}

