//! EmbedChromeContainer — the visual wrapper for any kind renderer (F-CR-06).
//!
//! Provides left border, indentation, and depth visual weight. Knows nothing
//! about the inner content. Matches ADR-0034's design.

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Style},
};

/// Simple chrome that draws a left border whose intensity can indicate depth.
pub struct EmbedChromeContainer {
    pub depth: u8,
    pub collapsed: bool,
}

impl EmbedChromeContainer {
    pub fn new(depth: u8, collapsed: bool) -> Self {
        Self { depth, collapsed }
    }

    /// Returns the inner area where the actual kind renderer should draw.
    pub fn inner(&self, area: Rect) -> Rect {
        if area.width <= 2 {
            return Rect::default();
        }
        Rect {
            x: area.x + 2,
            y: area.y,
            width: area.width - 2,
            height: area.height,
        }
    }

    pub fn render(&self, area: Rect, buf: &mut Buffer) {
        if area.width < 2 || area.height == 0 {
            return;
        }

        let border_style = if self.collapsed {
            Style::default().fg(Color::Rgb(100, 100, 110))
        } else {
            let g = 160u8.saturating_add(self.depth.saturating_mul(8));
            Style::default().fg(Color::Rgb(140, g.min(200), 220))
        };

        // Draw simple left border characters
        for y in area.y..area.bottom() {
            if let Some(cell) = buf.cell_mut((area.x, y)) {
                cell.set_char('│').set_style(border_style);
            }
            if let Some(cell) = buf.cell_mut((area.x + 1, y)) {
                cell.set_char(' ').set_style(border_style);
            }
        }
    }
}

//! EmbeddedEvent — the widget that renders any kind via the registry (F-CR-06).
//!
//! Receives an `EmbeddedEventEnvelope` (from F-CR-01), consults the
//! `NostrKindRegistry`, and wraps the chosen renderer in `EmbedChromeContainer`.

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Style},
    text::Line,
    widgets::Widget,
};

use nmp_content::embed_projection::EmbeddedEventEnvelope;

use super::embed_chrome_container::EmbedChromeContainer;
use super::NostrKindRegistry;

pub struct EmbeddedEvent<'a> {
    pub envelope: &'a EmbeddedEventEnvelope,
    pub registry: &'a NostrKindRegistry,
}

impl<'a> EmbeddedEvent<'a> {
    pub fn new(envelope: &'a EmbeddedEventEnvelope, registry: &'a NostrKindRegistry) -> Self {
        Self { envelope, registry }
    }

    pub fn preferred_height(&self, width: u16) -> u16 {
        if self.envelope.collapsed {
            return 1;
        }
        let inner_width = width.saturating_sub(2);
        let renderer = self.registry.resolve(&self.envelope.projection);
        renderer
            .preferred_height(&self.envelope.projection, inner_width)
            .max(1)
    }
}

impl Widget for EmbeddedEvent<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let chrome =
            EmbedChromeContainer::new(self.envelope.render_context.depth, self.envelope.collapsed);

        chrome.render(area, buf);
        let inner = chrome.inner(area);

        if self.envelope.collapsed {
            let reason = self
                .envelope
                .collapse_reason
                .as_deref()
                .unwrap_or("collapsed");
            Line::styled(
                format!("embedded event {reason}"),
                Style::default().fg(Color::Rgb(148, 163, 184)),
            )
            .render(inner, buf);
            return;
        }

        if inner.width == 0 || inner.height == 0 {
            return;
        }

        let renderer = self.registry.resolve(&self.envelope.projection);

        // Convert the wire RenderContextWire back to the in-memory RenderContext
        // for any recursive rendering the kind renderer may do.
        let ctx: nmp_content::context::RenderContext = (&self.envelope.render_context).into();

        renderer.render(&self.envelope.projection, &ctx, self.registry, inner, buf);
    }
}

use std::cell::RefCell;
use std::collections::{BTreeMap, HashSet};

use nmp_content::EventClaimSink;
use nmp_content::embed_projection::EmbeddedEventEnvelope;
use ratatui::{
    style::{Color, Modifier, Style},
    text::{Line, Span},
};
use ratatui_image::protocol::Protocol;

mod nostr_content_widget;

use super::{
    content_kind_registry::NostrKindRegistry,
    content_render_data::ContentRenderData,
    content_tree_wire::{ContentTreeWire, WireNode},
    nostr_media_grid::NostrMediaGrid,
    nostr_mention_chip::NostrMentionChip,
    nostr_quote_card::NostrQuoteCard,
    ratatui_text_wrap::{wrap_plain, wrap_prefixed, wrap_spans},
};

pub struct NostrContentView<'a> {
    tree: &'a ContentTreeWire,
    render_data: Option<&'a ContentRenderData>,
    media_images: &'a [(&'a str, &'a Protocol)],
    kind_registry: Option<&'a NostrKindRegistry>,
    embedded_events: Option<&'a BTreeMap<String, EmbeddedEventEnvelope>>,
    claim_sink: Option<&'a dyn EventClaimSink>,
    consumer_id: Option<&'a str>,
    // Per-render-pass seen-set. `Widget::render` consumes `self`, so the widget
    // is built fresh by the builder each frame — this set is naturally scoped
    // to a single render pass and dedups multiple references to the same URI
    // within one frame (D8: edge-triggered by render, no polling).
    claimed_this_frame: RefCell<HashSet<String>>,
}

impl<'a> NostrContentView<'a> {
    pub fn new(tree: &'a ContentTreeWire) -> Self {
        Self {
            tree,
            render_data: None,
            media_images: &[],
            kind_registry: None,
            embedded_events: None,
            claim_sink: None,
            consumer_id: None,
            claimed_this_frame: RefCell::new(HashSet::new()),
        }
    }

    pub fn render_data(mut self, render_data: Option<&'a ContentRenderData>) -> Self {
        self.render_data = render_data;
        self
    }

    pub fn media_images(mut self, images: &'a [(&'a str, &'a Protocol)]) -> Self {
        self.media_images = images;
        self
    }

    pub fn kind_registry(mut self, registry: Option<&'a NostrKindRegistry>) -> Self {
        self.kind_registry = registry;
        self
    }

    pub fn embedded_events(
        mut self,
        events: Option<&'a BTreeMap<String, EmbeddedEventEnvelope>>,
    ) -> Self {
        self.embedded_events = events;
        self
    }

    /// Optional host-side sink used to initiate an upstream fetch the first
    /// time a `nostr:` event URI is encountered in a render pass (ADR-0034 /
    /// M16). Defaults to `None`, which preserves fixture-only behaviour: no
    /// claims are issued and only pre-populated `embedded_events` resolve.
    pub fn claim_sink(mut self, sink: Option<&'a dyn EventClaimSink>) -> Self {
        self.claim_sink = sink;
        self
    }

    /// Optional consumer identifier passed alongside each `claim` call so the
    /// kernel can refcount per-host. Defaults to `None`; if either this or
    /// `claim_sink` is unset, the claim path is skipped entirely.
    pub fn consumer_id(mut self, id: Option<&'a str>) -> Self {
        self.consumer_id = id;
        self
    }

    pub fn lines(&self, width: usize) -> Vec<Line<'static>> {
        let mut lines = Vec::new();
        let mut root_pos = 0usize;
        while root_pos < self.tree.roots.len() {
            let root = self.tree.roots[root_pos];
            let Some(node) = self.tree.node(root) else {
                root_pos += 1;
                continue;
            };
            if is_inline_root(node) {
                let inline = self.collect_inline_roots(&mut root_pos);
                if !inline.is_empty() {
                    lines.extend(wrap_spans(inline, width));
                }
            } else {
                self.append_node(root, width, &mut lines);
                root_pos += 1;
            }
        }
        if lines.is_empty() {
            lines.push(Line::from(""));
        }
        lines
    }

    fn collect_inline_roots(&self, root_pos: &mut usize) -> Vec<Span<'static>> {
        let mut inline = Vec::new();
        while *root_pos < self.tree.roots.len() {
            let root = self.tree.roots[*root_pos];
            let Some(node) = self.tree.node(root) else {
                *root_pos += 1;
                continue;
            };
            if !is_inline_root(node) {
                break;
            }
            self.append_inline_node(root, &mut inline);
            *root_pos += 1;
        }
        inline
    }

    pub fn preferred_height(&self, width: usize) -> u16 {
        self.tree
            .roots
            .iter()
            .map(|root| self.node_height(*root, width))
            .sum::<u16>()
            .max(1)
    }

    fn append_node(&self, index: usize, width: usize, lines: &mut Vec<Line<'static>>) {
        let Some(node) = self.tree.node(index) else {
            return;
        };
        match node {
            WireNode::Paragraph { children } => {
                self.append_paragraph(children, width, lines);
            }
            WireNode::Heading { level, children } => {
                let prefix = "#".repeat((*level).clamp(1, 6) as usize);
                let mut spans = vec![Span::styled(
                    format!("{prefix} "),
                    Style::default().fg(Color::Rgb(248, 250, 252)),
                )];
                spans.extend(self.inline_spans(children));
                lines.extend(wrap_spans(spans, width));
            }
            WireNode::BlockQuote { .. } | WireNode::EventRef(_) => {
                lines.extend(
                    NostrQuoteCard::new(self.tree, node)
                        .render_data(self.render_data)
                        .media_images(self.media_images)
                        .lines(width),
                );
            }
            WireNode::CodeBlock { info, body } => {
                let title = info.as_deref().unwrap_or("code");
                lines.push(Line::from(Span::styled(
                    format!("```{title}"),
                    Style::default().fg(Color::Rgb(148, 163, 184)),
                )));
                lines.extend(body.lines().map(|line| {
                    Line::from(Span::styled(
                        line.to_string(),
                        Style::default().fg(Color::Rgb(253, 186, 116)),
                    ))
                }));
                lines.push(Line::from(Span::styled(
                    "```",
                    Style::default().fg(Color::Rgb(148, 163, 184)),
                )));
            }
            WireNode::List {
                ordered_start,
                items,
            } => {
                for (idx, item) in items.iter().enumerate() {
                    let marker = ordered_start
                        .map(|start| format!("{}.", start + idx as u64))
                        .unwrap_or_else(|| "-".to_string());
                    let body = self.text_for_nodes(item);
                    lines.extend(wrap_prefixed(
                        &body,
                        width,
                        &format!("{marker} "),
                        muted_style(),
                    ));
                }
            }
            WireNode::Rule => lines.push(Line::from("─".repeat(width.min(48)))),
            WireNode::Media { urls, kind } => {
                lines.extend(
                    NostrMediaGrid::new(urls, kind)
                        .images(self.media_images)
                        .lines(width),
                );
            }
            WireNode::Image { alt, src, .. } => {
                let target = src.as_deref().unwrap_or("missing src");
                lines.extend(wrap_prefixed(
                    &format!("{alt} {target}"),
                    width,
                    "[image] ",
                    muted_style(),
                ));
            }
            _ => {
                let mut spans = Vec::new();
                self.append_inline_node(index, &mut spans);
                if spans.is_empty() {
                    let text = node.inline_label(self.tree);
                    if !text.is_empty() {
                        lines.extend(wrap_plain(&text, width));
                    }
                } else {
                    lines.extend(wrap_spans(spans, width));
                }
            }
        }
    }

    fn append_paragraph(&self, children: &[usize], width: usize, lines: &mut Vec<Line<'static>>) {
        let mut inline = Vec::new();
        for child in children {
            let Some(node) = self.tree.node(*child) else {
                continue;
            };
            if matches!(node, WireNode::EventRef(_)) {
                if !inline.is_empty() {
                    lines.extend(wrap_spans(std::mem::take(&mut inline), width));
                }
                lines.extend(
                    NostrQuoteCard::new(self.tree, node)
                        .render_data(self.render_data)
                        .media_images(self.media_images)
                        .lines(width),
                );
            } else {
                self.append_inline_node(*child, &mut inline);
            }
        }
        if !inline.is_empty() {
            lines.extend(wrap_spans(inline, width));
        }
    }

    fn inline_spans(&self, children: &[usize]) -> Vec<Span<'static>> {
        let mut spans = Vec::new();
        for child in children {
            self.append_inline_node(*child, &mut spans);
        }
        spans
    }

    fn append_inline_node(&self, index: usize, spans: &mut Vec<Span<'static>>) {
        let Some(node) = self.tree.node(index) else {
            return;
        };
        match node {
            WireNode::Text(text) => spans.push(Span::raw(text.clone())),
            WireNode::Mention(uri) => spans.push(
                NostrMentionChip::new(uri)
                    .profile(self.render_data.and_then(|data| data.profile_for(uri)))
                    .span(),
            ),
            WireNode::EventRef(uri) => {
                let label = self
                    .render_data
                    .and_then(|data| data.event_for(uri))
                    .map(|event| format!("quote {}", event.author_label()))
                    .unwrap_or_else(|| format!("quote {}", short_id(&uri.primary_id)));
                spans.push(Span::styled(
                    label,
                    Style::default().fg(Color::Rgb(196, 181, 253)),
                ));
            }
            WireNode::Hashtag(tag) => spans.push(Span::styled(
                format!("#{tag}"),
                Style::default().fg(Color::Rgb(45, 212, 191)),
            )),
            WireNode::Url(url) => spans.push(Span::styled(
                url.clone(),
                Style::default().fg(Color::Rgb(96, 165, 250)),
            )),
            WireNode::Emoji { shortcode, .. } => spans.push(Span::raw(format!(":{shortcode}:"))),
            WireNode::Invoice { invoice } => spans.push(Span::styled(
                format!("[{} invoice]", invoice.kind.to_ascii_lowercase()),
                Style::default().fg(Color::Rgb(250, 204, 21)),
            )),
            WireNode::InlineCode(code) => spans.push(Span::styled(
                format!("`{code}`"),
                Style::default().fg(Color::Rgb(253, 186, 116)),
            )),
            WireNode::Emphasis { children } => {
                let start = spans.len();
                for child in children {
                    self.append_inline_node(*child, spans);
                }
                for span in &mut spans[start..] {
                    span.style = span.style.add_modifier(Modifier::ITALIC);
                }
            }
            WireNode::Strong { children } => {
                let start = spans.len();
                for child in children {
                    self.append_inline_node(*child, spans);
                }
                for span in &mut spans[start..] {
                    span.style = span.style.add_modifier(Modifier::BOLD);
                }
            }
            WireNode::Link { children, href } => {
                let start = spans.len();
                if children.is_empty() {
                    spans.push(Span::styled(
                        href.clone().unwrap_or_default(),
                        Style::default().fg(Color::Rgb(96, 165, 250)),
                    ));
                } else {
                    for child in children {
                        self.append_inline_node(*child, spans);
                    }
                    for span in &mut spans[start..] {
                        span.style = span.style.fg(Color::Rgb(96, 165, 250));
                    }
                }
            }
            WireNode::Image { alt, src, .. } => {
                let target = src.as_deref().unwrap_or("missing src");
                spans.push(Span::styled(
                    format!("[image: {alt} {target}]"),
                    Style::default().fg(Color::Rgb(186, 230, 253)),
                ));
            }
            WireNode::Media { urls, kind } => spans.push(Span::styled(
                format!("[{} media: {}]", kind.to_ascii_lowercase(), urls.len()),
                Style::default().fg(Color::Rgb(186, 230, 253)),
            )),
            WireNode::SoftBreak => spans.push(Span::raw(" ")),
            WireNode::HardBreak => spans.push(Span::raw("\n")),
            WireNode::Paragraph { children }
            | WireNode::Heading { children, .. }
            | WireNode::BlockQuote { children } => {
                for child in children {
                    self.append_inline_node(*child, spans);
                }
            }
            _ => {
                let text = node.inline_label(self.tree);
                if !text.is_empty() {
                    spans.push(Span::raw(text));
                }
            }
        }
    }

    fn text_for_nodes(&self, children: &[usize]) -> String {
        children
            .iter()
            .filter_map(|idx| self.tree.node(*idx))
            .map(|node| node.inline_label(self.tree))
            .filter(|text| !text.is_empty())
            .collect::<Vec<_>>()
            .join("\n")
    }

    fn node_height(&self, index: usize, width: usize) -> u16 {
        let Some(node) = self.tree.node(index) else {
            return 0;
        };
        match node {
            WireNode::Paragraph { children } => self.paragraph_height(children, width),
            WireNode::Media { urls, kind } => NostrMediaGrid::new(urls, kind)
                .images(self.media_images)
                .preferred_height()
                .saturating_add(1),
            WireNode::Image { src: Some(src), .. } => {
                NostrMediaGrid::new(std::slice::from_ref(src), "image")
                    .images(self.media_images)
                    .preferred_height()
                    .saturating_add(1)
            }
            WireNode::EventRef(_) | WireNode::BlockQuote { .. } => {
                NostrQuoteCard::new(self.tree, node)
                    .render_data(self.render_data)
                    .media_images(self.media_images)
                    .preferred_height(width)
                    .saturating_add(1)
            }
            _ => {
                let mut lines = Vec::new();
                self.append_node(index, width, &mut lines);
                lines.len().max(1) as u16
            }
        }
    }

    fn paragraph_height(&self, children: &[usize], width: usize) -> u16 {
        let mut inline = Vec::new();
        let mut height = 0u16;
        for child in children {
            match self.tree.node(*child) {
                Some(WireNode::EventRef(_) | WireNode::Media { .. } | WireNode::Image { .. }) => {
                    height = height.saturating_add(nonempty_wrapped_height(
                        std::mem::take(&mut inline),
                        width,
                    ));
                    height = height.saturating_add(self.node_height(*child, width));
                }
                Some(_) => self.append_inline_node(*child, &mut inline),
                None => {}
            }
        }
        height.saturating_add(nonempty_wrapped_height(inline, width))
    }
}

fn nonempty_wrapped_height(spans: Vec<Span<'static>>, width: usize) -> u16 {
    wrap_spans(spans, width)
        .into_iter()
        .filter(|line| line.spans.iter().any(|span| !span.content.is_empty()))
        .count() as u16
}

#[rustfmt::skip]
fn is_inline_root(node: &WireNode) -> bool {
    use WireNode::*;
    !matches!(node, Paragraph { .. } | Heading { .. } | BlockQuote { .. } | CodeBlock { .. } | List { .. } | Rule | Media { .. } | Image { .. } | EventRef(_))
}

fn short_id(id: &str) -> String {
    if id.len() > 12 {
        return format!("{}…{}", &id[..6], &id[id.len() - 6..]);
    }
    id.to_string()
}

fn muted_style() -> Style {
    Style::default().fg(Color::Rgb(148, 163, 184))
}

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    text::Line,
    widgets::{Paragraph, Widget, Wrap},
};

use super::super::{
    content_kind_registry::EmbeddedEvent,
    content_tree_wire::{WireNode, WireUri},
    nostr_media_grid::NostrMediaGrid,
    nostr_quote_card::NostrQuoteCard,
    ratatui_text_wrap::wrap_spans,
};
use super::{is_inline_root, NostrContentView};

impl Widget for NostrContentView<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let mut cursor = area.y;
        let mut root_pos = 0usize;
        while root_pos < self.tree.roots.len() {
            let root = self.tree.roots[root_pos];
            let Some(node) = self.tree.node(root) else {
                root_pos += 1;
                continue;
            };
            if is_inline_root(node) {
                let inline = self.collect_inline_roots(&mut root_pos);
                self.render_lines(
                    wrap_spans(inline, area.width as usize),
                    area,
                    buf,
                    &mut cursor,
                );
            } else {
                self.render_node(root, area, buf, &mut cursor);
                root_pos += 1;
            }
            if cursor >= area.bottom() {
                break;
            }
        }
        if cursor == area.y {
            Paragraph::new("").render(area, buf);
        }
    }
}

impl NostrContentView<'_> {
    fn render_node(&self, index: usize, area: Rect, buf: &mut Buffer, cursor: &mut u16) {
        let Some(node) = self.tree.node(index) else {
            return;
        };
        match node {
            WireNode::Paragraph { children } => self.render_paragraph(children, area, buf, cursor),
            WireNode::Media { urls, kind } => self.render_media(urls, kind, area, buf, cursor),
            WireNode::Image { src, .. } => {
                if let Some(src) = src {
                    self.render_media(std::slice::from_ref(src), "image", area, buf, cursor);
                }
            }
            WireNode::EventRef(uri) => {
                if !self.render_embedded_event(uri, area, buf, cursor) {
                    self.render_quote(node, area, buf, cursor);
                }
            }
            WireNode::BlockQuote { .. } => {
                self.render_quote(node, area, buf, cursor);
            }
            _ => {
                let lines = {
                    let mut out = Vec::new();
                    self.append_node(index, area.width as usize, &mut out);
                    out
                };
                self.render_lines(lines, area, buf, cursor);
            }
        }
    }

    fn render_paragraph(&self, children: &[usize], area: Rect, buf: &mut Buffer, cursor: &mut u16) {
        let mut inline = Vec::new();
        for child in children {
            let Some(node) = self.tree.node(*child) else {
                continue;
            };
            match node {
                WireNode::EventRef(uri) => {
                    self.render_lines(
                        wrap_spans(std::mem::take(&mut inline), area.width as usize),
                        area,
                        buf,
                        cursor,
                    );
                    if !self.render_embedded_event(uri, area, buf, cursor) {
                        self.render_node(*child, area, buf, cursor);
                    }
                }
                WireNode::Media { .. } | WireNode::Image { .. } => {
                    self.render_lines(
                        wrap_spans(std::mem::take(&mut inline), area.width as usize),
                        area,
                        buf,
                        cursor,
                    );
                    self.render_node(*child, area, buf, cursor);
                }
                _ => self.append_inline_node(*child, &mut inline),
            }
        }
        self.render_lines(wrap_spans(inline, area.width as usize), area, buf, cursor);
    }

    fn render_embedded_event(
        &self,
        uri: &WireUri,
        area: Rect,
        buf: &mut Buffer,
        cursor: &mut u16,
    ) -> bool {
        let Some(registry) = self.kind_registry else {
            return false;
        };
        // Edge-triggered fetch: when both sink and consumer are configured,
        // ask the host to claim this URI before we look up the envelope. The
        // claim is independent of cache state — warm cache claims refcount
        // upstream as a near no-op; cold cache claims trigger the OneshotApi
        // path and the envelope surfaces in a later snapshot. Dedup per render
        // pass via the seen-set so multiple references to the same URI in one
        // frame collapse into a single host call.
        if let (Some(sink), Some(consumer)) = (self.claim_sink, self.consumer_id) {
            let mut seen = self.claimed_this_frame.borrow_mut();
            if seen.insert(uri.uri.clone()) {
                sink.claim(&uri.uri, consumer);
            }
        }
        let Some(envelope) = self.envelope_for(uri) else {
            return false;
        };
        let widget = EmbeddedEvent::new(envelope, registry);
        let height = widget.preferred_height(area.width);
        let rect = take_area(area, cursor, height);
        if rect.is_empty() {
            return true;
        }
        widget.render(rect, buf);
        *cursor = rect.bottom().saturating_add(1).min(area.bottom());
        true
    }

    fn envelope_for(
        &self,
        uri: &WireUri,
    ) -> Option<&nmp_content::embed_projection::EmbeddedEventEnvelope> {
        let events = self.embedded_events?;
        events.get(&uri.primary_id).or_else(|| events.get(&uri.uri))
    }

    fn render_quote(&self, node: &WireNode, area: Rect, buf: &mut Buffer, cursor: &mut u16) {
        let card = NostrQuoteCard::new(self.tree, node)
            .render_data(self.render_data)
            .media_images(self.media_images);
        let height = card.preferred_height(area.width as usize);
        let rect = take_area(area, cursor, height);
        if rect.is_empty() {
            return;
        }
        card.render(rect, buf);
        *cursor = rect.bottom().saturating_add(1).min(area.bottom());
    }

    fn render_media(
        &self,
        urls: &[String],
        kind: &str,
        area: Rect,
        buf: &mut Buffer,
        cursor: &mut u16,
    ) {
        let grid = NostrMediaGrid::new(urls, kind).images(self.media_images);
        let rect = take_area(area, cursor, grid.preferred_height());
        if rect.is_empty() {
            return;
        }
        grid.render(rect, buf);
        *cursor = rect.bottom().saturating_add(1).min(area.bottom());
    }

    fn render_lines(
        &self,
        lines: Vec<Line<'static>>,
        area: Rect,
        buf: &mut Buffer,
        cursor: &mut u16,
    ) {
        let lines = lines
            .into_iter()
            .filter(|line| line.spans.iter().any(|span| !span.content.is_empty()))
            .collect::<Vec<_>>();
        if lines.is_empty() {
            return;
        }
        let rect = take_area(area, cursor, lines.len() as u16);
        if rect.is_empty() {
            return;
        }
        Paragraph::new(lines)
            .wrap(Wrap { trim: false })
            .render(rect, buf);
        *cursor = rect.bottom();
    }
}

fn take_area(area: Rect, cursor: &mut u16, wanted_height: u16) -> Rect {
    if *cursor >= area.bottom() || wanted_height == 0 {
        return Rect::new(area.x, area.bottom(), area.width, 0);
    }
    let available = area.bottom().saturating_sub(*cursor);
    Rect {
        x: area.x,
        y: *cursor,
        width: area.width,
        height: wanted_height.min(available),
    }
}

package org.nmp.registry

import kotlinx.serialization.SerialName
import kotlinx.serialization.Serializable

/**
 * Wire type for a Nostr user profile, decoded from the `nmp-profile`
 * projection emitted by the kernel.
 *
 * `npub` and `npubShort` are always Rust-formatted — never reformat
 * them in Kotlin.
 */
@Serializable
data class ProfileWire(
    @SerialName("pubkey") val pubkey: String,
    @SerialName("display_name") val displayName: String? = null,
    @SerialName("about") val about: String? = null,
    @SerialName("picture_url") val pictureUrl: String? = null,
    @SerialName("nip05") val nip05: String? = null,
    /** Full bech32 `npub1…` string. Use for copy / share. */
    @SerialName("npub") val npub: String,
    /** Rust-truncated npub (e.g. `npub1abcd…wxyz`). Display only. */
    @SerialName("npub_short") val npubShort: String,
) {
    /** Stable display label: `displayName` if set, else `npubShort`. */
    val display: String get() = displayName?.takeIf { it.isNotEmpty() } ?: npubShort

    /** Avatar URL string; `null` when no picture is set or empty. */
    val avatarUrl: String? get() = pictureUrl?.takeIf { it.isNotEmpty() }
}

