/**
 * Compact author header: avatar, display name, and optional NIP-05 badge.
 *
 * The most common pattern in note feeds and thread views. Tap routes
 * through [onTap] so this component can be used in any navigation stack.
 *
 * Depends on `compose/user-avatar`, `compose/user-name`, `compose/user-nip05`.
 */
@Composable
fun NostrUserCard(
    profile: ProfileWire,
    avatarSize: Dp = 40.dp,
    onTap: ((String) -> Unit)? = null,
    modifier: Modifier = Modifier,
) {
    val tapModifier = if (onTap != null) {
        modifier.clickable { onTap(profile.pubkey) }
    } else {
        modifier
    }

    Row(
        verticalAlignment = Alignment.CenterVertically,
        modifier = tapModifier.semantics(mergeDescendants = true) {
            contentDescription = "${profile.display}, profile"
        },
    ) {
        NostrAvatar(profile = profile, size = avatarSize)
        Spacer(Modifier.width(10.dp))
        Column {
            NostrProfileName(profile = profile)
            NostrNip05Badge(profile = profile)
        }
    }
}

/// Wire type for a Nostr user profile, decoded from the Rust-owned profile
/// projection before it reaches the Ratatui view layer.
///
/// `npub` and `npub_short` are already Rust-formatted. TUI code should render
/// them as provided rather than reformatting keys locally.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ProfileWire {
    pub pubkey: String,
    pub display_name: Option<String>,
    pub about: Option<String>,
    pub picture_url: Option<String>,
    pub nip05: Option<String>,
    pub npub: String,
    pub npub_short: String,
}

impl ProfileWire {
    pub fn display(&self) -> &str {
        non_empty(self.display_name.as_deref()).unwrap_or(self.npub_short.as_str())
    }

    pub fn nip05(&self) -> Option<&str> {
        non_empty(self.nip05.as_deref())
    }

    pub fn picture_url(&self) -> Option<&str> {
        non_empty(self.picture_url.as_deref())
    }

    pub fn initials(&self) -> String {
        let label = self.display();
        let mut letters = label
            .split_whitespace()
            .filter_map(|part| part.chars().next())
            .filter(|ch| ch.is_alphanumeric())
            .take(2)
            .collect::<String>();
        if letters.is_empty() {
            letters = self.npub_short.chars().take(2).collect();
        }
        letters.to_uppercase()
    }
}

fn non_empty(value: Option<&str>) -> Option<&str> {
    value.map(str::trim).filter(|value| !value.is_empty())
}

use ratatui::{
    buffer::Buffer,
    layout::{Alignment, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Widget},
};
use ratatui_image::{protocol::Protocol, Image};

use super::profile_wire::ProfileWire;

const PALETTE: [Color; 8] = [
    Color::Rgb(244, 114, 182),
    Color::Rgb(56, 189, 248),
    Color::Rgb(52, 211, 153),
    Color::Rgb(251, 191, 36),
    Color::Rgb(167, 139, 250),
    Color::Rgb(248, 113, 113),
    Color::Rgb(45, 212, 191),
    Color::Rgb(250, 204, 21),
];

/// Circular-ish terminal avatar with deterministic identicon fallback.
///
/// Terminals render cells, not real circles, so this widget uses a compact
/// bordered tile with profile initials and a stable pubkey-derived accent.
pub struct NostrAvatar<'a> {
    profile: &'a ProfileWire,
    image: Option<&'a Protocol>,
    border_style: Style,
}

impl<'a> NostrAvatar<'a> {
    pub fn new(profile: &'a ProfileWire) -> Self {
        Self {
            profile,
            image: None,
            border_style: Style::default().fg(accent_for(&profile.pubkey)),
        }
    }

    pub fn image(mut self, image: Option<&'a Protocol>) -> Self {
        self.image = image;
        self
    }

    pub fn border_style(mut self, style: Style) -> Self {
        self.border_style = style;
        self
    }
}

impl Widget for NostrAvatar<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let accent = accent_for(&self.profile.pubkey);
        let initials = self.profile.initials();
        let block = Block::default()
            .borders(Borders::ALL)
            .border_style(self.border_style)
            .style(Style::default().bg(Color::Reset));
        let inner = block.inner(area);
        block.render(area, buf);

        if inner.is_empty() {
            return;
        }
        if let Some(image) = self.image {
            Image::new(image).allow_clipping(true).render(inner, buf);
            return;
        }

        let fill = Style::default()
            .fg(Color::Black)
            .bg(accent)
            .add_modifier(Modifier::BOLD);
        let line = Line::from(Span::styled(initials, fill));
        Paragraph::new(line)
            .alignment(Alignment::Center)
            .style(fill)
            .render(center_line(inner), buf);
    }
}

fn accent_for(pubkey: &str) -> Color {
    let hash = pubkey.bytes().fold(5381usize, |acc, byte| {
        ((acc << 5).wrapping_add(acc)) ^ byte as usize
    });
    PALETTE[hash % PALETTE.len()]
}

fn center_line(area: Rect) -> Rect {
    Rect {
        x: area.x,
        y: area.y + area.height.saturating_sub(1) / 2,
        width: area.width,
        height: 1,
    }
}

