/// NIP-05 verified identity badge.
pub struct NostrNip05Badge {
    label: String,
    style: Style,
}

impl NostrNip05Badge {
    pub fn new(nip05: &str) -> Option<Self> {
        Some(Self {
            label: display_nip05(nip05)?,
            style: Style::default().fg(Color::Rgb(45, 212, 191)),
        })
    }

    pub fn from_profile(profile: &ProfileWire) -> Option<Self> {
        Self::new(profile.nip05()?)
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }

    pub fn line(&self) -> Line<'static> {
        Line::from(vec![
            Span::styled("✓ ", self.style.add_modifier(Modifier::BOLD)),
            Span::styled(self.label.clone(), self.style),
        ])
    }
}

impl Widget for NostrNip05Badge {
    fn render(self, area: Rect, buf: &mut Buffer) {
        Paragraph::new(self.line()).render(area, buf);
    }
}

fn display_nip05(nip05: &str) -> Option<String> {
    let trimmed = nip05.trim();
    if trimmed.is_empty() {
        return None;
    }
    match trimmed.strip_prefix("_@") {
        Some(domain) if !domain.is_empty() => Some(domain.to_string()),
        _ => Some(trimmed.to_string()),
    }
}

use ratatui::{
    buffer::Buffer,
    layout::Rect,
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Widget},
};

use super::profile_wire::ProfileWire;

/// Display-only npub chip.
///
/// Clipboard writes are a host capability. Keep this widget pure and handle
/// copy actions in the surrounding TUI input loop.
pub struct NostrNpubChip<'a> {
    profile: &'a ProfileWire,
    style: Style,
}

impl<'a> NostrNpubChip<'a> {
    pub fn new(profile: &'a ProfileWire) -> Self {
        Self {
            profile,
            style: Style::default()
                .fg(Color::Rgb(186, 230, 253))
                .bg(Color::Rgb(15, 23, 42)),
        }
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }

    pub fn label(&self) -> String {
        format!(" {} ", self.profile.npub_short)
    }
}

impl Widget for NostrNpubChip<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let block = Block::default()
            .borders(Borders::ALL)
            .border_style(self.style)
            .style(self.style);
        let inner = block.inner(area);
        block.render(area, buf);
        Paragraph::new(Line::from(Span::styled(self.label(), self.style))).render(inner, buf);
    }
}

use ratatui::{
    buffer::Buffer,
    layout::{Constraint, Layout, Rect},
    style::{Color, Style},
    text::Line,
    widgets::{Block, Borders, Paragraph, Widget},
};
use ratatui_image::protocol::Protocol;

use super::{
    nostr_avatar::NostrAvatar, nostr_nip05_badge::NostrNip05Badge,
    nostr_profile_name::NostrProfileName, profile_wire::ProfileWire,
};

/// Compact author header: avatar, display name, and optional NIP-05 badge.
pub struct NostrUserCard<'a> {
    profile: &'a ProfileWire,
    avatar_image: Option<&'a Protocol>,
    style: Style,
}

impl<'a> NostrUserCard<'a> {
    pub fn new(profile: &'a ProfileWire) -> Self {
        Self {
            profile,
            avatar_image: None,
            style: Style::default().fg(Color::White).bg(Color::Rgb(12, 16, 28)),
        }
    }

    pub fn avatar_image(mut self, image: Option<&'a Protocol>) -> Self {
        self.avatar_image = image;
        self
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }
}

impl Widget for NostrUserCard<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let block = Block::default()
            .borders(Borders::ALL)
            .border_style(Style::default().fg(Color::Rgb(30, 41, 59)))
            .style(self.style);
        let inner = block.inner(area);
        block.render(area, buf);
        if inner.is_empty() {
            return;
        }

        let chunks = Layout::horizontal([Constraint::Length(14), Constraint::Min(0)]).split(inner);
        NostrAvatar::new(self.profile)
            .image(self.avatar_image)
            .render(chunks[0], buf);

        let text_area = inset(chunks[1], 1, 0);
        let name = NostrProfileName::new(self.profile).line();
        let badge = NostrNip05Badge::from_profile(self.profile)
            .map(|badge| badge.line())
            .unwrap_or_else(|| Line::from(""));

        Paragraph::new(vec![name, badge])
            .style(self.style)
            .render(text_area, buf);
    }
}

fn inset(area: Rect, x: u16, y: u16) -> Rect {
    Rect {
        x: area.x.saturating_add(x),
        y: area.y.saturating_add(y),
        width: area.width.saturating_sub(x),
        height: area.height.saturating_sub(y),
    }
}
